const PASSAGE_DB = {
  rla: [],
  social_studies: [],
  science: [],
  math_word_problems: [],
};

function loadPassageBank() {
  const base = __dirname;
  // primary expected location (backend/data) with fallback to root /data
  const rootData = path.resolve(__dirname, '..', 'data');
  const rla =
    readJsonSafe(path.join(base, 'data', 'rla_passages.json')) ||
    readJsonSafe(path.join(rootData, 'rla_passages.json')) ||
    [];
  const ss =
    readJsonSafe(path.join(base, 'data', 'social_studies_passages.json')) ||
    readJsonSafe(path.join(rootData, 'social_studies_passages.json')) ||
    [];
  const sci =
    readJsonSafe(path.join(base, 'data', 'science_passages.json')) ||
    readJsonSafe(path.join(rootData, 'science_passages.json')) ||
    [];
  const mathWP =
    readJsonSafe(path.join(base, 'data', 'math_word_problems.json')) ||
    readJsonSafe(path.join(rootData, 'math_word_problems.json')) ||
    [];

  PASSAGE_DB.rla = Array.isArray(rla) ? rla : [];
  PASSAGE_DB.social_studies = Array.isArray(ss) ? ss : [];
  PASSAGE_DB.science = Array.isArray(sci) ? sci : [];
  PASSAGE_DB.math_word_problems = Array.isArray(mathWP) ? mathWP : [];
  try {
    console.info(
      '[Passages] RLA:',
      PASSAGE_DB.rla.length,
      'SS:',
      PASSAGE_DB.social_studies.length,
      'SCI:',
      PASSAGE_DB.science.length,
      'MATH WP:',
      PASSAGE_DB.math_word_problems.length
    );
  } catch {}
}

function pickPassageFor(subject, { topic = '', difficulty = '' } = {}) {
  if (!subject) return null;
  const sub = subject.toLowerCase();
  let pool = [];
  if (sub.includes('rla')) pool = PASSAGE_DB.rla;
  else if (sub.includes('social')) pool = PASSAGE_DB.social_studies;
  else if (sub.includes('science')) pool = PASSAGE_DB.science;
  else return null;
  if (!Array.isArray(pool) || !pool.length) return null;

  const topicLc = topic ? topic.toLowerCase() : '';
  let candidates = pool;
  if (topicLc) {
    const topicMatches = pool.filter(
      (p) =>
        (p.topic && String(p.topic).toLowerCase().includes(topicLc)) ||
        (p.area && String(p.area).toLowerCase().includes(topicLc)) ||
        (p.label && String(p.label).toLowerCase().includes(topicLc))
    );
    if (topicMatches.length) candidates = topicMatches;
  }
  if (difficulty) {
    const diffMatches = candidates.filter(
      (p) =>
        String(p.difficulty || '').toLowerCase() === difficulty.toLowerCase()
    );
    if (diffMatches.length) candidates = diffMatches;
  }
  const idx = Math.floor(Math.random() * candidates.length);
  const chosen = candidates[idx];
  if (!chosen) return null;
  return {
    id: chosen.id || null,
    title: chosen.title || chosen.label || '',
    author: chosen.author || '',
    year: chosen.year || '',
    text: chosen.text || chosen.passage || chosen.problem || '',
    topic: chosen.topic || chosen.area || '',
  };
}

function sciencePassageMatchesCategory(passage, category) {
  if (!passage || !category) return true;

  const categoryAliases = {
    'life science': [
      'life science',
      'biology',
      'evolution',
      'ecology',
      'microbiology',
      'genetics',
      'botany',
      'physiology',
      'anatomy',
      'medicine',
    ],
    'physical science': [
      'physical science',
      'physics',
      'chemistry',
      'electricity',
      'magnetism',
      'light',
      'motion',
      'radioactivity',
      'atom',
      'electromagnetic',
    ],
    'earth & space science': [
      'earth & space science',
      'earth science',
      'space science',
      'astronomy',
      'geology',
      'environmental science',
      'conservation',
      'climate',
      'ocean',
      'sea',
      'river',
      'mountain',
      'earth',
    ],
  };

  const acceptedLabels = categoryAliases[String(category).toLowerCase()] || [
    String(category).toLowerCase(),
  ];
  const haystack = [passage.topic, passage.area, passage.label, passage.title]
    .filter(Boolean)
    .map((value) => String(value).toLowerCase())
    .join(' ');

  return acceptedLabels.some((label) => haystack.includes(label));
}

function pickSciencePassageForCategory(category, usedIds = new Set()) {
  const pool = Array.isArray(PASSAGE_DB.science) ? PASSAGE_DB.science : [];
  if (!pool.length) return null;

  const categoryPool = pool.filter((passage) =>
    sciencePassageMatchesCategory(passage, category)
  );
  let candidates = categoryPool.filter((passage) => !usedIds.has(passage.id));

  if (!candidates.length) {
    candidates = categoryPool.length
      ? categoryPool
      : pool.filter((passage) => !usedIds.has(passage.id));
  }
  if (!candidates.length) {
    candidates = pool;
  }

  const chosen = candidates[Math.floor(Math.random() * candidates.length)];
  if (!chosen) return null;
  if (chosen.id) usedIds.add(chosen.id);

  return {
    id: chosen.id || null,
    title: chosen.title || chosen.label || '',
    author: chosen.author || '',
    year: chosen.year || '',
    text: chosen.text || chosen.passage || '',
    topic: chosen.topic || chosen.area || '',
  };
}

function buildSciencePassageStimulus(passage) {
  if (!passage?.text) return '';

  const titleLine = passage.title
    ? `<p><strong>${String(passage.title)}</strong></p>`
    : '';
  const bylineParts = [passage.author, passage.year].filter(Boolean);
  const byline = bylineParts.length
    ? `<p><em>${bylineParts.join(', ')}</em></p>`
    : '';

  return normalizeTables(
    `<div class="passage-text">${titleLine}${byline}<p>${String(passage.text)}</p></div>`
  );
}

// Generate a set of science literacy (reading comprehension) questions from a bank passage
async function generateScienceLiteracySet(
  numQuestions = 5,
  aiOptions = {},
  options = {}
) {
  try {
    const passage =
      options.passageSource ||
      pickSciencePassageForCategory(options.category, options.usedPassageIds);
    if (!passage || !passage.text) return [];
    const capped = Math.max(1, Math.min(8, numQuestions));
    // Build optional skillIntent focus paragraph
    let skillFocus = '';
    if (options.skillIntent === 'evidence-tradeoff') {
      skillFocus = `\nSPECIAL FOCUS: At least half the questions should ask the student to evaluate competing claims, determine whether evidence supports or contradicts a conclusion, or weigh the strength of two opposing scientific arguments.\n`;
    } else if (options.skillIntent === 'experimental-design') {
      skillFocus = `\nSPECIAL FOCUS: At least half the questions should ask about experimental design — identifying variables (independent, dependent, controlled), recognizing flaws or confounds, evaluating the validity of an experimental procedure, or explaining the purpose of a control group.\n`;
    }
    const prompt = `You are a GED Science exam creator.
Using ONLY the passage below, create ${capped} multiple-choice Science literacy questions.
The GED Science test is a COMPREHENSION exam — students must interpret text and data, NOT recall facts.

Focus on comprehension, inference, author's purpose, interpretation of scientific claims, and evaluation of evidence.
Do NOT create numeracy/calculation questions. Avoid asking for formula application.
NEVER write a pure definition question like "What is the name of…" or "What is the term for…".
Every question MUST require the student to USE information from the passage to answer correctly.
Do not reference images, charts, or graphs that are not in the passage text.
${skillFocus}
Each question must have 4 answer options with exactly one correct marked.
Return JSON ONLY with {"questions": [ {"questionText": "...", "answerOptions": [ {"text": "...", "isCorrect": true, "rationale": "..." }, {"text": "...", "isCorrect": false, "rationale": "..."} ] } ] }.
Do not wrap JSON in markdown fences.

PASSAGE TITLE: ${passage.title || 'Untitled passage'}
PASSAGE CONTEXT: ${passage.topic || options.category || 'Science'}

PASSAGE:\n"""${passage.text}"""`;

    const schema = {
      type: 'OBJECT',
      properties: {
        questions: {
          type: 'ARRAY',
          items: {
            type: 'OBJECT',
            properties: {
              questionText: { type: 'STRING' },
              answerOptions: {
                type: 'ARRAY',
                items: {
                  type: 'OBJECT',
                  properties: {
                    text: { type: 'STRING' },
                    isCorrect: { type: 'BOOLEAN' },
                    rationale: { type: 'STRING' },
                  },
                  required: ['text', 'isCorrect', 'rationale'],
                },
              },
            },
            required: ['questionText', 'answerOptions'],
          },
        },
      },
      required: ['questions'],
    };
    const res = await callAI(prompt, schema, aiOptions);
    const qs = Array.isArray(res?.questions) ? res.questions : [];
    return qs.map((q) => ({
      ...enforceWordCapsOnItem(q, 'Science'),
      passage: buildSciencePassageStimulus(passage),
      questionText: normalizeTables(q.questionText || ''),
      type: 'passage',
      itemType: 'passage',
      qaProfileKey: 'literacy',
      source: 'sciencePassageBank:literacy',
      passageBankId: passage.id || null,
      passageTitle: passage.title || '',
      topicTags: passage.topic ? [passage.topic] : [],
    }));
  } catch (e) {
    try {
      console.warn('[Science-Literacy] generation failed:', e?.message || e);
    } catch {}
    return [];
  }
}

function buildScienceNumeracyTemplateItem(template) {
  if (!template) return null;
  const passageHtml = normalizeTables(
    `${template.stem || ''}${template.passage || ''}`
  );
  const item = {
    id: `science_numeracy_${template.id}_${Date.now()}`,
    passage: passageHtml,
    questionText: template.questionText,
    questionType: 'short_constructed_response',
    responseType: template.responseType || 'numeric',
    correctAnswer: template.correctAnswer,
    tolerance: template.tolerance,
    qaProfileKey: template.qaProfileKey || 'numeracy',
    source: 'scienceTemplate:numeracy',
    difficulty: template.difficulty || 'medium',
    topicTags: template.topicTags || [],
    type: 'passage',
    templateSourceId: template.id,
  };
  return enforceWordCapsOnItem(item, 'Science');
}

function buildScienceScenarioCluster(template) {
  if (!template) return null;
  const shared = normalizeTables(template.sharedPassage || '');
  const base = {
    passage: shared,
    qaProfileKey: template.qaProfileKey || 'reasoning',
    type: 'passage',
    itemType: 'passage',
    source: 'scienceTemplate:scenario',
    groupId: template.groupId || template.id,
    stimulusId: template.id,
    clusterLabel: template.clusterLabel,
    difficulty: template.difficulty || 'medium',
    topicTags: template.topicTags || [],
    questionType: 'multiple_choice_single',
    templateSourceId: template.id,
  };
  return template.questions.map((q, idx) =>
    enforceWordCapsOnItem(
      {
        ...base,
        id: `science_scenario_${template.id}_${idx}_${Date.now()}`,
        questionText: q.questionText,
        answerOptions: Array.isArray(q.answerOptions) ? q.answerOptions : [],
      },
      'Science'
    )
  );
}

function buildScienceShortResponseItem(template) {
  if (!template) return null;
  const item = {
    id: `science_short_${template.id}_${Date.now()}`,
    questionText: template.questionText,
    questionType: 'short_constructed_response',
    responseType: 'short',
    expectedFeatures: template.expectedFeatures || [],
    sampleAnswer: template.sampleAnswer || '',
    qaProfileKey: template.qaProfileKey || 'literacy',
    source: 'scienceTemplate:short',
    difficulty: template.difficulty || 'medium',
    rubricHints: template.expectedFeatures || [],
    type: 'freeResponse',
    templateSourceId: template.id,
  };
  return enforceWordCapsOnItem(item, 'Science');
}

function scienceTemplateMatchesCategory(template, category) {
  if (!template || !category) return true;

  const categoryAliases = {
    'life science': ['life science', 'biology'],
    'physical science': ['physical science', 'physics', 'chemistry'],
    'earth & space science': [
      'earth & space science',
      'earth science',
      'space science',
      'earth systems',
    ],
  };

  const normalizedCategory = String(category).toLowerCase();
  const acceptedLabels = new Set(
    categoryAliases[normalizedCategory] || [normalizedCategory]
  );

  const declaredCategories = Array.isArray(template.subjectAreas)
    ? template.subjectAreas
    : Array.isArray(template.categories)
      ? template.categories
      : [];

  if (declaredCategories.length > 0) {
    return declaredCategories.some((entry) =>
      acceptedLabels.has(String(entry).toLowerCase())
    );
  }

  const tags = Array.isArray(template.topicTags)
    ? template.topicTags.map((tag) => String(tag).toLowerCase())
    : [];
  if (tags.some((tag) => acceptedLabels.has(tag))) {
    return true;
  }

  const scenarioCategoryMap = {
    scenario_genetics_punnett: ['Life Science'],
    scenario_water_quality: ['Life Science', 'Earth & Space Science'],
    scenario_free_fall_lab: ['Physical Science'],
  };

  return (scenarioCategoryMap[template.id] || []).some((entry) =>
    acceptedLabels.has(String(entry).toLowerCase())
  );
}

function pickScienceTemplateByCategory(list, category, excludeIds = new Set()) {
  const pool = list.filter(
    (item) =>
      !excludeIds.has(item.id) && scienceTemplateMatchesCategory(item, category)
  );
  if (!pool.length) return null;
  return pool[Math.floor(Math.random() * pool.length)];
}

function normalizeScienceQuestionReuseText(value) {
  return String(value || '')
    .toLowerCase()
    .replace(/<[^>]*>/g, ' ')
    .replace(/&nbsp;/g, ' ')
    .replace(/[^a-z0-9]+/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
}

function buildScienceQuestionReuseKey(question, fallbackPrefix = 'science') {
  if (!question || typeof question !== 'object') return '';

  const questionText = normalizeScienceQuestionReuseText(
    question.questionText || question.question || ''
  );
  const imagePath =
    question.stimulusImage?.src ||
    question.imageUrl ||
    question.imageURL ||
    question.image ||
    '';
  const templateId =
    question.templateSourceId || question.bankFingerprint || '';

  if (questionText && imagePath) {
    return `${fallbackPrefix}:img:${imagePath}:${questionText}`;
  }
  if (questionText && templateId) {
    return `${fallbackPrefix}:tpl:${templateId}:${questionText}`;
  }
  if (questionText) {
    return `${fallbackPrefix}:txt:${questionText}`;
  }
  return templateId ? `${fallbackPrefix}:id:${templateId}` : '';
}

function instantiateScienceNumeracyTemplate(
  category,
  excludeIds = new Set(),
  usedTemplateIds = new Set()
) {
  const reservedIds = new Set([...excludeIds, ...usedTemplateIds]);
  const tpl = pickScienceTemplateByCategory(
    SCI_NUMERIC_TABLE_ITEMS,
    category,
    reservedIds
  );
  if (!tpl) return null;
  excludeIds.add(tpl.id);
  usedTemplateIds.add(tpl.id);
  return buildScienceNumeracyTemplateItem(tpl);
}

function instantiateScienceScenarioCluster(category, excludeIds = new Set()) {
  const reservedIds = new Set(excludeIds);
  reservedIds.add('scenario_genetics_punnett');
  let tpl = pickScienceTemplateByCategory(
    SCIENTIFIC_SCENARIO_SETS,
    category,
    reservedIds
  );
  if (!tpl && excludeIds.size > 0) {
    excludeIds.clear();
    tpl = pickScienceTemplateByCategory(
      SCIENTIFIC_SCENARIO_SETS,
      category,
      new Set(['scenario_genetics_punnett'])
    );
  }
  if (!tpl) return null;
  excludeIds.add(tpl.id);
  return buildScienceScenarioCluster(tpl);
}

function instantiateScienceScenarioClusterForSlot(
  slot,
  excludeIds = new Set()
) {
  if (slot?.group === 'life_genetics') {
    const geneticsTemplate = SCIENTIFIC_SCENARIO_SETS.find(
      (item) => item.id === 'scenario_genetics_punnett'
    );
    if (geneticsTemplate) {
      return buildScienceScenarioCluster(geneticsTemplate);
    }
  }
  return instantiateScienceScenarioCluster(slot?.category, excludeIds);
}

const SCIENCE_COMPREHENSIVE_PRIORITY_IMAGE_PATHS = new Set([
  '/images/Science/ged_scince_fig_13_0001.png',
  '/images/Science/ged_sci_1_1024x847_0001.png',
  '/images/Science/unclassified_0052.png',
  '/images/Science/unclassified_0041.png',
  '/images/Science/unclassified_0032.png',
  '/images/Science/unclassified_0033.png',
  '/images/Science/licensed_image_0009.jpg',
  '/images/Science/unclassified_0007.png',
  '/images/Science/unclassified_0027.png',
]);

function scienceImageEntrySupportsStimulus(entry, stimulusType) {
  if (!entry || !stimulusType) return true;
  const supported = Array.isArray(entry.stimulusTypes)
    ? entry.stimulusTypes.map((value) => String(value).toLowerCase())
    : [];
  if (!supported.length) return true;
  if (stimulusType === 'image') {
    return supported.includes('image') || supported.includes('diagram');
  }
  if (stimulusType === 'diagram') {
    return supported.includes('diagram') || supported.includes('image');
  }
  if (stimulusType === 'chart') {
    return supported.includes('chart') || supported.includes('graph');
  }
  if (stimulusType === 'table') {
    return supported.includes('table') || supported.includes('chart');
  }
  return supported.includes(String(stimulusType).toLowerCase());
}

function countUnusedScienceImageQuestions(
  image,
  numQuestions,
  usedQuestionKeys = new Set()
) {
  const entry = getScienceImageBankEntry(image);
  if (!Array.isArray(entry?.questions) || !entry.questions.length) return 0;

  return entry.questions
    .filter((question) => {
      const questionKey = buildScienceQuestionReuseKey(
        {
          ...question,
          imageUrl: image?.filePath,
          stimulusImage: image?.filePath ? { src: image.filePath } : undefined,
        },
        'science-image'
      );
      return questionKey && !usedQuestionKeys.has(questionKey);
    })
    .slice(0, Math.max(1, numQuestions || 1)).length;
}

function pickScienceImageForSlot(
  slot,
  usedPaths = new Set(),
  usedQuestionKeys = new Set()
) {
  const scienceCatalog = getSeededScienceImages(
    Array.isArray(curatedImages) && curatedImages.length
      ? curatedImages
      : IMAGE_DB
  );
  if (!scienceCatalog.length) return null;

  const groupPathMap = {
    life_genetics: ['/images/Science/dominance_genetics_0001.png'],
    life_image1: ['/images/Science/unclassified_0033.png'],
    phys_image1: ['/images/Science/unclassified_0027.png'],
    earth_diag1: ['/images/Science/ged_scince_fig_13_0001.png'],
  };

  const preferredPaths = groupPathMap[slot?.group] || [];
  const preferred = scienceCatalog.find(
    (img) =>
      preferredPaths.includes(img.filePath) &&
      !usedPaths.has(img.filePath) &&
      hasHandAuthoredScienceImageQuestions(img) &&
      countUnusedScienceImageQuestions(
        img,
        slot?.questionsNeeded,
        usedQuestionKeys
      ) >= Math.max(1, slot?.questionsNeeded || 1) &&
      scienceImageEntrySupportsStimulus(
        getScienceImageBankEntry(img),
        slot?.stimulusType
      )
  );
  if (preferred) {
    usedPaths.add(preferred.filePath);
    return preferred;
  }

  const reusablePreferred = scienceCatalog
    .filter((img) => {
      if (!img?.filePath) return false;
      if (!SCIENCE_COMPREHENSIVE_PRIORITY_IMAGE_PATHS.has(img.filePath)) {
        return false;
      }
      const entry = getScienceImageBankEntry(img);
      if (!entry || !hasHandAuthoredScienceImageQuestions(img)) return false;
      if (
        slot?.category &&
        Array.isArray(entry.subjectAreas) &&
        !entry.subjectAreas.includes(slot.category)
      ) {
        return false;
      }
      if (!scienceImageEntrySupportsStimulus(entry, slot?.stimulusType)) {
        return false;
      }
      if (
        slot?.group !== 'life_genetics' &&
        Array.isArray(entry.topicTags) &&
        entry.topicTags.includes('punnett-square')
      ) {
        return false;
      }
      return (
        countUnusedScienceImageQuestions(
          img,
          slot?.questionsNeeded,
          usedQuestionKeys
        ) >= Math.max(1, slot?.questionsNeeded || 1)
      );
    })
    .sort((left, right) => {
      const leftRank = getScienceImageBankEntry(left)?.qualityRank || 999;
      const rightRank = getScienceImageBankEntry(right)?.qualityRank || 999;
      return leftRank - rightRank;
    })[0];

  if (reusablePreferred?.filePath) {
    return reusablePreferred;
  }

  const fallback = scienceCatalog
    .filter((img) => {
      if (!img?.filePath || usedPaths.has(img.filePath)) return false;
      const entry = getScienceImageBankEntry(img);
      if (!entry || !hasHandAuthoredScienceImageQuestions(img)) return false;
      if (
        slot?.category &&
        Array.isArray(entry.subjectAreas) &&
        !entry.subjectAreas.includes(slot.category)
      ) {
        return false;
      }
      if (!scienceImageEntrySupportsStimulus(entry, slot?.stimulusType)) {
        return false;
      }
      if (
        slot?.group !== 'life_genetics' &&
        Array.isArray(entry.topicTags) &&
        entry.topicTags.includes('punnett-square')
      ) {
        return false;
      }
      return (
        countUnusedScienceImageQuestions(
          img,
          slot?.questionsNeeded,
          usedQuestionKeys
        ) >= Math.max(1, slot?.questionsNeeded || 1)
      );
    })
    .sort((left, right) => {
      const leftPreferred = SCIENCE_COMPREHENSIVE_PRIORITY_IMAGE_PATHS.has(
        left.filePath
      )
        ? 0
        : 1;
      const rightPreferred = SCIENCE_COMPREHENSIVE_PRIORITY_IMAGE_PATHS.has(
        right.filePath
      )
        ? 0
        : 1;
      if (leftPreferred !== rightPreferred) {
        return leftPreferred - rightPreferred;
      }
      const leftRank = getScienceImageBankEntry(left)?.qualityRank || 999;
      const rightRank = getScienceImageBankEntry(right)?.qualityRank || 999;
      return leftRank - rightRank;
    })[0];

  if (fallback?.filePath) {
    usedPaths.add(fallback.filePath);
  }
  return fallback || null;
}

function buildTrustedScienceImageQuestionSet(
  slot,
  usedPaths = new Set(),
  usedQuestionKeys = new Set()
) {
  if (
    slot?.group === 'life_genetics' ||
    !['image', 'diagram', 'chart', 'table'].includes(slot?.stimulusType)
  ) {
    return [];
  }

  const image = pickScienceImageForSlot(slot, usedPaths, usedQuestionKeys);
  if (!image) return [];

  return getHandAuthoredScienceImageQuestions({
    image,
    category: slot.category,
    numQuestions: slot.questionsNeeded,
    slotStimulusType: slot.stimulusType,
    usedQuestionKeys,
  }).slice(0, slot.questionsNeeded);
}

function instantiateScienceShortResponse(excludeIds = new Set()) {
  const tpl = getRandomScienceShortResponse(excludeIds);
  if (!tpl) return null;
  excludeIds.add(tpl.id);
  return buildScienceShortResponseItem(tpl);
}

function injectScienceTemplateItems(
  items,
  { scenarioSets = 0, shortResponses = 0, targetCount = 12 } = {}
) {
  if (!Array.isArray(items)) return [];
  const templateItems = [];
  if (scenarioSets > 0) {
    const scenarioExclude = new Set();
    for (let i = 0; i < scenarioSets; i++) {
      const cluster = instantiateScienceScenarioCluster(null, scenarioExclude);
      if (!cluster || !cluster.length) break;
      templateItems.push(...cluster);
    }
  }
  if (shortResponses > 0) {
    const shortExclude = new Set();
    for (let i = 0; i < shortResponses; i++) {
      const sr = instantiateScienceShortResponse(shortExclude);
      if (!sr) break;
      templateItems.push(sr);
    }
  }
  if (!templateItems.length) return items;
  const cappedTemplates = templateItems.slice(0, targetCount);
  const remainingSlots = Math.max(0, targetCount - cappedTemplates.length);
  const trimmedBase = items.slice(0, remainingSlots);
  return [...cappedTemplates, ...trimmedBase];
}

function pickMathWordProblemTemplate(category = null, difficulty = null) {
  const pool = getMathWordProblemPool({ category, difficulty });
  if (!Array.isArray(pool) || !pool.length) return null;
  return pool[Math.floor(Math.random() * pool.length)];
}

function normalizeMathTemplateText(value) {
  return String(value || '').toLowerCase();
}

function getMathTemplateCategories(template) {
  const combined = [
    template?.id,
    template?.label,
    template?.area,
    template?.problem,
  ]
    .map(normalizeMathTemplateText)
    .join(' ');
  const categories = new Set();

  if (
    /math_algebra_|algebraic reasoning|equation|inequalit|expression|variable|linear|age problem|cost equation/.test(
      combined
    )
  ) {
    categories.add('Expressions, Equations, and Inequalities');
  }

  if (/graph|function|slope|coordinate|ordered pair/.test(combined)) {
    categories.add('Graphing & Functions');
  }

  if (
    /math_geometry_|geometry and measurement|perimeter|area|volume|circumference|triangle|rectangle|diameter|radius|box|flooring|wall/.test(
      combined
    )
  ) {
    categories.add('Geometry');
  }

  if (
    /math_ratio_|math_percent_|math_money_|math_interest_|math_work_|math_distance_|quantitative reasoning|rates and proportions|ratio|proportion|percent|discount|markup|tax|tip|interest|commission|unit price|budget|rate/.test(
      combined
    )
  ) {
    categories.add('Ratios, Proportions, and Percents');
  }

  if (
    /math_data_|data analysis|average|mean|median|probability|histogram|scatter|table|chart/.test(
      combined
    )
  ) {
    categories.add('Data Analysis & Probability');
  }

  if (
    /math_fractions_|number operations|fraction|decimal|integer|mixed number/.test(
      combined
    )
  ) {
    categories.add('Number Operations');
  }

  return categories;
}

function templateMatchesMathCategory(template, category) {
  if (!category) return true;
  return getMathTemplateCategories(template).has(category);
}

function getMathWordProblemPool(criteria = {}) {
  const pool = Array.isArray(PASSAGE_DB.math_word_problems)
    ? PASSAGE_DB.math_word_problems
    : [];
  if (!pool.length) return [];

  const difficultyPool = criteria?.difficulty
    ? pool.filter((item) => item?.difficulty === criteria.difficulty)
    : pool;

  if (!criteria?.category) {
    return difficultyPool;
  }

  return difficultyPool.filter((item) =>
    templateMatchesMathCategory(item, criteria.category)
  );
}

function instantiateMathWordProblem(template) {
  if (!template) return null;
  // naive number jitter for uniqueness
  let problem = String(template.problem || '');
  const numbers = problem.match(/\b\d+(?:\.\d+)?\b/g) || [];
  const usedMap = new Map();
  numbers.forEach((num) => {
    if (usedMap.has(num)) return;
    const base = parseFloat(num);
    if (!isFinite(base)) return;
    const factor = 0.8 + Math.random() * 0.6; // 0.8 - 1.4
    let mutated = base;
    // keep smaller integers stable more often
    if (base > 5) mutated = Math.round(base * factor * 10) / 10;
    const replacement = mutated === base ? base : mutated;
    usedMap.set(num, replacement);
    problem = problem.replace(
      new RegExp(`\b${num}\b`, 'g'),
      String(replacement)
    );
  });
  // Build distractors heuristically
  const correct = String(template.answer || '').trim();
  const distractors = [];
  function variantAnswer(ans) {
    if (/\d/.test(ans)) {
      const m = ans.match(/\d+(?:\.\d+)?/);
      if (m) {
        const val = parseFloat(m[0]);
        const plus = val + (Math.abs(val) < 10 ? 1 : Math.round(val * 0.1));
        const minus = Math.max(
          val - (Math.abs(val) < 10 ? 1 : Math.round(val * 0.1)),
          0
        );
        return [
          ans.replace(m[0], String(plus)),
          ans.replace(m[0], String(minus)),
        ];
      }
    }
    return [ans + ' (approx.)', 'Not enough information'];
  }
  const varAns = variantAnswer(correct);
  varAns.forEach((v) => {
    if (v !== correct) distractors.push(v);
  });
  if (distractors.length < 3) distractors.push('Cannot be determined');
  const answerOptions = [
    {
      text: correct,
      isCorrect: true,
      rationale: `Correct answer based on provided scenario; derived from original template '${
        template.label || template.id
      }'.`,
    },
    ...distractors.slice(0, 3).map((d) => ({
      text: d,
      isCorrect: false,
      rationale: 'Plausible but incorrect.',
    })),
  ];
  return {
    id: `math_wp_${template.id}_${Date.now()}`,
    questionText: problem,
    passage: '',
    answerOptions,
    type: 'standalone',
  };
}

// ============================================================================
// SCIENCE & MATH SANITIZER FUNCTIONS (Strict Enforcement)
// ============================================================================

/**
 * Detects if a question requires written explanation/response
 */
function looksLikeWrittenExplanation(questionText) {
  if (!questionText || typeof questionText !== 'string') return false;
  const text = questionText.toLowerCase();
  return /(explain|describe|why|in\s*\d+\s*(?:-|–|to)?\s*\d*\s*sentences|write\s+(?:a|an|your)|response|give\s+a\s+reason|justify|discuss)/i.test(
    text
  );
}

/**
 * Checks if answer is numeric
 */
function isNumericAnswer(answer) {
  if (typeof answer !== 'string') return false;
  const trimmed = answer.trim();
  // Allow numbers, decimals, negative signs, percent, fractions
  return /^[\d\.\-\/%\s\(\)]+$/.test(trimmed) && /\d/.test(trimmed);
}

/**
 * Generate multiple choice options from an explanatory question prompt
 */
function generateMultipleChoiceFromExplanatoryQuestion(q) {
  const questionText = q.questionText || q.question || q.prompt || '';

  // Extract the core concept/topic
  const topic = questionText.slice(0, 100);

  // Generate plausible distractors based on common patterns
  const options = [];

  if (/temperature|heat/i.test(questionText)) {
    options.push(
      {
        text: 'Heat energy is transferred from cold to hot objects',
        isCorrect: false,
        rationale: 'Incorrect - heat flows from hot to cold',
      },
      {
        text: 'Heat energy is transferred from hot to cold objects',
        isCorrect: true,
        rationale:
          'Correct - heat naturally flows from higher to lower temperature',
      },
      {
        text: 'Temperature and heat are the same thing',
        isCorrect: false,
        rationale:
          'Incorrect - temperature measures average kinetic energy, heat is energy transfer',
      },
      {
        text: 'Heat transfer does not occur in a vacuum',
        isCorrect: false,
        rationale: 'Incorrect - radiation can transfer heat through a vacuum',
      }
    );
  } else if (/cell|organism|living/i.test(questionText)) {
    options.push(
      {
        text: 'All cells have a nucleus',
        isCorrect: false,
        rationale: 'Incorrect - prokaryotic cells lack a nucleus',
      },
      {
        text: 'Cells are the basic unit of life',
        isCorrect: true,
        rationale: 'Correct - all living things are made of cells',
      },
      {
        text: 'Viruses are considered living cells',
        isCorrect: false,
        rationale: 'Incorrect - viruses are not cells and require hosts',
      },
      {
        text: 'Only plants have cells',
        isCorrect: false,
        rationale: 'Incorrect - all organisms have cells',
      }
    );
  } else if (/force|motion|velocity/i.test(questionText)) {
    options.push(
      {
        text: 'An object at rest will remain at rest unless acted upon by a force',
        isCorrect: true,
        rationale: "Correct - Newton's first law of motion",
      },
      {
        text: 'Objects naturally slow down without any force',
        isCorrect: false,
        rationale: 'Incorrect - friction is the force causing this',
      },
      {
        text: 'Heavier objects always fall faster',
        isCorrect: false,
        rationale: 'Incorrect - in vacuum all objects fall at same rate',
      },
      {
        text: 'Force and velocity are the same thing',
        isCorrect: false,
        rationale:
          'Incorrect - force causes acceleration, not velocity directly',
      }
    );
  } else {
    // Generic options
    options.push(
      {
        text: 'Option A: Based on scientific principles',
        isCorrect: true,
        rationale: 'Correct answer',
      },
      {
        text: 'Option B: Common misconception',
        isCorrect: false,
        rationale: 'Plausible but incorrect',
      },
      {
        text: 'Option C: Alternative theory',
        isCorrect: false,
        rationale: 'Not supported by evidence',
      },
      {
        text: 'Option D: Incomplete understanding',
        isCorrect: false,
        rationale: 'Missing key factors',
      }
    );
  }

  return options;
}

/**
 * Main sanitizer for Science and Math questions
 * Converts written-response questions to multiple choice
 */
function sanitizeScienceAndMathQuestions(questions, subject = '') {
  if (!Array.isArray(questions)) return questions;

  const isScienceOrMath = /science|math/i.test(subject);
  if (!isScienceOrMath) return questions;

  return questions.map((q) => {
    const questionText = q.questionText || q.question || q.prompt || '';

    // Check if it looks like written explanation
    if (looksLikeWrittenExplanation(questionText)) {
      console.log(
        `[Sanitizer][${subject}] Converting written-response question to multiple-choice`
      );

      // Convert to multiple choice
      q.questionType = 'multiple_choice';
      q.questionType = 'multiple_choice_single';
      q.responseType = 'mc';
      q.type = q.type === 'passage' ? 'passage' : 'standalone';

      // Generate or ensure answer options exist
      if (!Array.isArray(q.answerOptions) || q.answerOptions.length === 0) {
        q.answerOptions = generateMultipleChoiceFromExplanatoryQuestion(q);
      }

      // Remove constructed response fields
      delete q.expectedFeatures;
      delete q.sampleAnswer;
      delete q.rubricHints;
    }

    // For fill-in questions without options, ensure they are numeric only
    if (!Array.isArray(q.answerOptions) || q.answerOptions.length === 0) {
      if (q.correctAnswer && !isNumericAnswer(q.correctAnswer)) {
        console.log(
          `[Sanitizer][${subject}] Non-numeric fill-in detected, converting to multiple-choice`
        );

        // Convert to multiple choice
        q.questionType = 'multiple_choice_single';
        q.responseType = 'mc';
        q.answerOptions = generateMultipleChoiceFromExplanatoryQuestion(q);
      } else if (q.correctAnswer) {
        // It's numeric, enforce numeric response type
        q.responseType = 'numeric';
        q.questionType = 'short_constructed_response';
      }
    }

    return q;
  });
}

/**
 * Check if passage and chart/table mismatch (unrelated content)
 */
function passageChartMismatch(q) {
  const hasPassage = !!(
    q.passage &&
    typeof q.passage === 'string' &&
    q.passage.trim().length > 50
  );
  const hasTableOrChart =
    /<table/i.test(q.questionText || '') ||
    /chart|graph/i.test(q.questionText || '');

  // If both exist, check if they're related
  if (hasPassage && hasTableOrChart) {
    const passage = (q.passage || '').toLowerCase();
    const question = (q.questionText || '').toLowerCase();

    // Look for data references in passage that match table content
    const passageHasDataRef =
      /(data|table|chart|graph|figure|shown|above|below)/i.test(passage);
    const questionRefsPassage = /(passage|text|reading|according to)/i.test(
      question
    );

    // If passage has no data reference AND question has table, likely mismatch
    if (!passageHasDataRef && hasTableOrChart && !questionRefsPassage) {
      console.log('[Sanitizer] Detected passage-chart mismatch');
      return true;
    }
  }

  return false;
}

