async function buildScoreSummary(userId) {
  try {
    const { loadScoresSafe } = require('./services/profileData');
    if (typeof loadScoresSafe === 'function') {
      const scoreData = await loadScoresSafe(userId);
      const recentScoresDashboard =
        scoreData &&
        typeof scoreData.recentScoresDashboard === 'object' &&
        scoreData.recentScoresDashboard !== null
          ? scoreData.recentScoresDashboard
          : {};

      const legacyScores = {};
      if (Array.isArray(scoreData?.bySubject)) {
        legacyScores.bySubject = scoreData.bySubject;
      }
      if (Array.isArray(scoreData?.bySubtopic)) {
        legacyScores.bySubtopic = scoreData.bySubtopic;
      }

      return {
        recentScoresDashboard,
        legacyScores,
      };
    }
  } catch (err) {
    console.warn('buildScoreSummary fallback', err?.message || err);
  }

  return {
    recentScoresDashboard: {},
    legacyScores: {},
  };
}

function normalizeTestDate(value) {
  if (!value) {
    return '';
  }
  if (value instanceof Date) {
    return value.toISOString().slice(0, 10);
  }
  if (typeof value === 'string') {
    return value;
  }
  try {
    const asDate = new Date(value);
    if (!Number.isNaN(asDate.getTime())) {
      return asDate.toISOString().slice(0, 10);
    }
  } catch (err) {
    // ignore
  }
  return String(value);
}

async function buildProfileBundle(userId) {
  if (!userId) {
    throw new Error('buildProfileBundle requires a userId');
  }

  const hasNameColumn = await profilesHasNameColumn();

  let profileRow = null;
  try {
    const columnList = hasNameColumn
      ? 'user_id, name, timezone, reminder_enabled, font_size, onboarding_complete'
      : 'user_id, timezone, reminder_enabled, font_size, onboarding_complete';
    const result = await db.query(
      `SELECT ${columnList} FROM profiles WHERE user_id = $1`,
      [userId]
    );
    profileRow = result.rows[0] || null;
  } catch (err) {
    console.error('Failed to load profile row', err?.message || err);
  }

  let displayName = null;
  if (hasNameColumn) {
    displayName = profileRow?.name ?? null;
  }

  if (!displayName) {
    try {
      const userRow = await db.oneOrNone(
        `SELECT name FROM users WHERE id = $1`,
        [userId]
      );
      displayName = userRow?.name ?? null;
    } catch (err) {
      console.warn('Failed to load user name', err?.message || err);
    }
  }

  const profileData = profileRow || {
    user_id: userId,
    timezone: 'America/New_York',
    reminder_enabled: true,
    font_size: null,
    onboarding_complete: false,
  };

  const testPlanTable = await getTestPlanTableName();
  let planRows = [];
  try {
    const result = await db.query(
      `SELECT subject, test_date, test_location, passed, not_scheduled FROM ${testPlanTable} WHERE user_id = $1 ORDER BY subject`,
      [userId]
    );
    planRows = result.rows;
  } catch (err) {
    console.error('Failed to load test plan rows', err?.message || err);
  }

  const testPlan = planRows.map((r) => ({
    subject: r.subject,
    testDate: normalizeTestDate(r.test_date),
    testLocation: r.test_location || '',
    passed: !!r.passed,
    notScheduled: !!r.not_scheduled,
  }));

  const { optionTable, selectionTable } = await getChallengeTables();

  let allChallenges = [];
  try {
    const result = await db.query(
      `SELECT id, subject, subtopic, label FROM ${optionTable} ORDER BY subject, subtopic, id`
    );
    allChallenges = result.rows;
  } catch (err) {
    console.error('Failed to load challenge options', err?.message || err);
  }

  // Determine whether to use DB catalog or fallback list
  // - Use env ALWAYS_USE_FALLBACK_CHALLENGES=true to force fallback
  // - Otherwise require a minimum catalog size (default 20) before trusting DB
  const alwaysUseFallback =
    String(process.env.ALWAYS_USE_FALLBACK_CHALLENGES || '').toLowerCase() ===
    'true';
  const minSize = (() => {
    const n = Number(process.env.MIN_CHALLENGE_CATALOG_SIZE || 20);
    return Number.isFinite(n) && n > 0 ? Math.floor(n) : 20;
  })();
  const hasSufficientCatalog =
    Array.isArray(allChallenges) && allChallenges.length >= minSize;
  const effectiveAllChallenges = alwaysUseFallback
    ? FALLBACK_PROFILE_CHALLENGES
    : hasSufficientCatalog
      ? allChallenges
      : FALLBACK_PROFILE_CHALLENGES;

  let chosen = [];
  try {
    const result = await db.query(
      `SELECT challenge_id FROM ${selectionTable} WHERE user_id = $1`,
      [userId]
    );
    chosen = result.rows;
  } catch (err) {
    console.error('Failed to load selected challenges', err?.message || err);
  }

  const chosenSet = new Set(chosen.map((r) => String(r.challenge_id)));

  let challengeOptions = effectiveAllChallenges.map((opt) => ({
    id: String(opt.id),
    subject: opt.subject || opt.subject_alias || opt.subject,
    subtopic: opt.subtopic,
    label: opt.label,
    selected: chosenSet.has(String(opt.id)),
  }));

  // Safety: if the query probes or mapping above produced an empty list,
  // always fall back to the in-memory catalog so the UI has options.
  if (!Array.isArray(challengeOptions) || challengeOptions.length === 0) {
    try {
      challengeOptions = FALLBACK_PROFILE_CHALLENGES.map((opt) => ({
        id: String(opt.id),
        subject: opt.subject || opt.subject_alias || opt.subject,
        subtopic: opt.subtopic,
        label: opt.label,
        selected: chosenSet.has(String(opt.id)),
      }));
    } catch (_) {
      challengeOptions = [];
    }
  }

  const { recentScoresDashboard, legacyScores } =
    await buildScoreSummary(userId);

  return {
    profile: {
      id: userId,
      name: displayName,
      timezone: profileData.timezone || 'America/New_York',
      reminderEnabled:
        profileData.reminder_enabled !== undefined &&
        profileData.reminder_enabled !== null
          ? !!profileData.reminder_enabled
          : true,
      fontSize: profileData.font_size,
      onboardingComplete: !!profileData.onboarding_complete,
      icon: profileData.icon || '/icons/student-svgrepo-com.svg',
    },
    // Both testPlan (normalized for UI) and raw tests for debugging/compat
    testPlan,
    tests: planRows,
    challengeOptions,
    recentScoresDashboard: recentScoresDashboard || {},
    scores: legacyScores || {},
  };
}

// ═══════════════════════════════════════════════════════════════════════
//  buildCoachContext — gather rich analytics for AI coach prompts
// ═══════════════════════════════════════════════════════════════════════
async function buildCoachContext(userId) {
  const bundle = await buildProfileBundle(userId);

  // Domain mastery from quiz_attempt_items
  let domainMastery = [];
  try {
    const dm = await pool.query(
      `SELECT i.subject, i.domain,
              COUNT(*)::int AS total,
              SUM(CASE WHEN i.is_correct THEN 1 ELSE 0 END)::int AS correct,
              ROUND(AVG(CASE WHEN i.is_correct THEN 1.0 ELSE 0.0 END)*100,1) AS accuracy_pct,
              AVG(i.time_spent_ms)::int AS avg_time_ms,
              SUM(CASE WHEN i.confidence='sure' AND NOT i.is_correct THEN 1 ELSE 0 END)::int AS misconceptions,
              SUM(CASE WHEN i.confidence='guessing' AND i.is_correct THEN 1 ELSE 0 END)::int AS lucky_guesses
       FROM quiz_attempt_items i
       JOIN quiz_attempts a ON a.id = i.attempt_id
       WHERE a.user_id = $1 AND i.domain IS NOT NULL
       GROUP BY i.subject, i.domain ORDER BY accuracy_pct ASC`,
      [userId]
    );
    domainMastery = dm.rows;
  } catch (_) {}

  // Weakest areas (top 10)
  let weakestAreas = [];
  try {
    const wa = await pool.query(
      `SELECT i.subject, i.domain, i.topic,
              COUNT(*)::int AS total,
              SUM(CASE WHEN i.is_correct THEN 1 ELSE 0 END)::int AS correct,
              ROUND(AVG(CASE WHEN i.is_correct THEN 1.0 ELSE 0.0 END)*100,1) AS accuracy_pct
       FROM quiz_attempt_items i
       JOIN quiz_attempts a ON a.id = i.attempt_id
       WHERE a.user_id = $1 AND (i.domain IS NOT NULL OR i.topic IS NOT NULL)
       GROUP BY i.subject, i.domain, i.topic HAVING COUNT(*)>=3
       ORDER BY accuracy_pct ASC LIMIT 10`,
      [userId]
    );
    weakestAreas = wa.rows;
  } catch (_) {}

  // Confidence calibration
  let confidenceData = { byConfidence: {}, calibrationScore: null };
  try {
    const cf = await pool.query(
      `SELECT i.confidence,
              COUNT(*)::int AS total,
              SUM(CASE WHEN i.is_correct THEN 1 ELSE 0 END)::int AS correct
       FROM quiz_attempt_items i
       JOIN quiz_attempts a ON a.id = i.attempt_id
       WHERE a.user_id = $1 AND i.confidence IS NOT NULL
       GROUP BY i.confidence`,
      [userId]
    );
    const byConf = {};
    for (const r of cf.rows) {
      byConf[r.confidence] = {
        total: r.total,
        correct: r.correct,
        accuracyPct: r.total > 0 ? Math.round((r.correct / r.total) * 100) : 0,
      };
    }
    const sure = byConf['sure'] || { total: 0, correct: 0 };
    const guessing = byConf['guessing'] || { total: 0, correct: 0 };
    const sureAcc = sure.total > 0 ? sure.correct / sure.total : 0.5;
    const guessAcc =
      guessing.total > 0 ? guessing.correct / guessing.total : 0.5;
    const totalConf = sure.total + guessing.total;
    const calibrationScore =
      totalConf > 0
        ? Math.round(
            ((sureAcc * sure.total + (1 - guessAcc) * guessing.total) /
              totalConf) *
              100
          )
        : null;
    confidenceData = { byConfidence: byConf, calibrationScore };
  } catch (_) {}

  // Score trends per subject
  let scoreTrends = {};
  try {
    const st = await pool.query(
      `SELECT subject, scaled_score, passed, attempted_at
       FROM quiz_attempts
       WHERE user_id = $1 AND scaled_score IS NOT NULL
       ORDER BY attempted_at ASC`,
      [userId]
    );
    const bySubj = {};
    for (const r of st.rows) {
      const s = r.subject || 'Unknown';
      if (!bySubj[s]) bySubj[s] = [];
      bySubj[s].push({
        scaledScore: parseInt(r.scaled_score) || 0,
        passed: r.passed,
        date: r.attempted_at,
      });
    }
    for (const [s, attempts] of Object.entries(bySubj)) {
      const scores = attempts.map((a) => a.scaledScore);
      const latest = scores[scores.length - 1] || 0;
      const best = Math.max(...scores);
      const growth = scores.length >= 2 ? latest - scores[0] : 0;
      scoreTrends[s] = {
        latest,
        best,
        growth,
        attemptCount: scores.length,
        passCount: attempts.filter((a) => a.passed).length,
      };
    }
  } catch (_) {}

  // Recent 5 attempts
  let recentAttempts = [];
  try {
    const ra = await pool.query(
      `SELECT subject, quiz_title, score, total_questions, scaled_score, passed, attempted_at
       FROM quiz_attempts WHERE user_id = $1
       ORDER BY attempted_at DESC LIMIT 5`,
      [userId]
    );
    recentAttempts = ra.rows;
  } catch (_) {}

  // Total quiz stats
  let totalQuizzes = 0;
  let totalQuestions = 0;
  try {
    const qs = await pool.query(
      `SELECT COUNT(*)::int AS quizzes, COALESCE(SUM(total_questions),0)::int AS questions
       FROM quiz_attempts WHERE user_id = $1`,
      [userId]
    );
    totalQuizzes = qs.rows[0]?.quizzes || 0;
    totalQuestions = qs.rows[0]?.questions || 0;
  } catch (_) {}

  // Subject status (passed)
  let subjectStatus = {};
  try {
    const ss = await pool.query(
      `SELECT subject, passed FROM user_subject_status WHERE user_id = $1`,
      [userId]
    );
    for (const r of ss.rows) subjectStatus[r.subject] = r.passed;
  } catch (_) {}

  // Test plan with days-until
  const testPlan = Array.isArray(bundle?.testPlan) ? bundle.testPlan : [];
  const now = new Date();
  const testPlanWithCountdown = testPlan.map((t) => {
    if (!t.testDate) return { ...t, daysUntil: null };
    const diff = Math.ceil(
      (new Date(t.testDate) - now) / (1000 * 60 * 60 * 24)
    );
    return { ...t, daysUntil: diff };
  });

  // Challenge selections
  const challengeOptions = Array.isArray(bundle?.challengeOptions)
    ? bundle.challengeOptions
    : [];
  const selectedChallenges = challengeOptions.filter((c) => c && c.selected);

  return {
    profile: bundle?.profile || {},
    testPlan: testPlanWithCountdown,
    selectedChallenges,
    domainMastery,
    weakestAreas,
    confidenceData,
    scoreTrends,
    recentAttempts,
    subjectStatus,
    totalQuizzes,
    totalQuestions,
  };
}

