// CORS configuration: prefer env var, fallback to hardcoded defaults
const defaultOrigins = [
  'https://ged-website.onrender.com',
  'https://ezged.netlify.app',
  'https://quiz.ez-ged.com',
  'http://localhost:8000', // For local testing
  'http://localhost:5173', // Vite dev server
];

const allowedOrigins = process.env.CORS_ORIGINS
  ? process.env.CORS_ORIGINS.split(',').map((o) => o.trim())
  : defaultOrigins;

// Pre-CORS diagnostic: log any POST to /generate-quiz to confirm it reaches Express
app.use((req, res, next) => {
  if (
    req.method === 'POST' &&
    (req.url === '/generate-quiz' || req.originalUrl === '/generate-quiz')
  ) {
    console.log('[pre-cors] POST /generate-quiz received', {
      origin: req.headers.origin || '(none)',
      host: req.headers.host,
    });
  }
  next();
});

const corsOptions = {
  origin: (origin, callback) => {
    // Allow requests with no origin (like mobile apps or curl requests)
    if (!origin) return callback(null, true);

    // Allow VS Code Simple Browser and localhost
    if (
      origin &&
      (origin.startsWith('vscode-webview://') ||
        origin.includes('localhost') ||
        origin.includes('127.0.0.1') ||
        origin.includes('onrender.com'))
    ) {
      return callback(null, true);
    }

    if (allowedOrigins.indexOf(origin) === -1) {
      const msg =
        'The CORS policy for this site does not allow access from the specified Origin.';
      console.warn(
        '[CORS] Blocked origin:',
        origin,
        'Allowed:',
        allowedOrigins
      );
      return callback(new Error(msg), false);
    }
    return callback(null, true);
  },
  credentials: true,
  optionsSuccessStatus: 200,
};
app.use(cors(corsOptions));

function shouldLogRequestPath(url = '') {
  const path = String(url || '').split('?')[0];
  return (
    path.startsWith('/api/') ||
    path === '/generate-quiz' ||
    path === '/score-essay' ||
    path === '/define-word'
  );
}

app.use((req, res, next) => {
  if (req.method === 'OPTIONS') return next();
  const url = req.originalUrl || req.url || '';
  if (!shouldLogRequestPath(url)) return next();

  const startedAt = Date.now();
  const method = req.method;
  const path = url;
  const userId = req.user?.id || req.user?.userId || req.user?.sub || 'anon';
  const ip =
    req.ip ||
    req.headers['x-forwarded-for'] ||
    req.socket?.remoteAddress ||
    'unknown';

  console.log(`[request:start] ${method} ${path} user=${userId} ip=${ip}`);

  res.on('finish', () => {
    const durationMs = Date.now() - startedAt;
    const status = res.statusCode;
    const outcome = status >= 200 && status < 400 ? 'success' : 'failed';
    console.log(
      `[request:${outcome}] ${method} ${path} status=${status} durationMs=${durationMs}`
    );
  });

  res.on('close', () => {
    if (!res.writableEnded) {
      const durationMs = Date.now() - startedAt;
      console.warn(
        `[request:aborted] ${method} ${path} durationMs=${durationMs}`
      );
    }
  });

  return next();
});

// Admin route access logging middleware
function logAdminAccess(req, res, next) {
  try {
    const timestamp = new Date().toISOString();
    const userId = req.user?.id || req.user?.userId || 'anon';
    const role = req.user?.role || 'none';
    const path = req.originalUrl || req.url;

    if (req.user) {
      console.log(
        `[admin-access] ${timestamp} user=${userId} role=${role} path=${path}`
      );
    } else {
      console.log(`[admin-access-anon] ${timestamp} path=${path}`);
    }
  } catch (err) {
    // Logging failure should not break the request
    console.error('[logAdminAccess] Error:', err);
  }
  next();
}

