// Student endpoint to join an organization with optional access code
app.post(
  '/api/student/select-organization',
  orgJoinLimiter,
  devAuth,
  ensureTestUserForNow,
  requireAuthInProd,
  authRequired,
  async (req, res) => {
    try {
      const userId = req.user?.id || req.user?.userId;
      if (!userId) {
        return res.status(401).json({ ok: false, error: 'unauthorized' });
      }

      const { organization_id, access_code } = req.body;

      if (!organization_id) {
        return res.status(400).json({
          ok: false,
          error: 'organization_id is required',
        });
      }

      // Fetch the organization
      const orgResult = await db.query(
        'SELECT id, name, access_code FROM organizations WHERE id = $1',
        [organization_id]
      );

      if (orgResult.rows.length === 0) {
        return res.status(404).json({
          ok: false,
          error: 'Organization not found',
        });
      }

      const org = orgResult.rows[0];

      // Phase 1.6 — seat enforcement (flag-gated, default OFF). Existing
      // members of the org are NEVER blocked; this only refuses NEW joins
      // beyond seat_limit. Orgs created before the migration default to
      // plan_tier='legacy' with seat_limit=NULL (unlimited), so today's
      // student joins are unaffected.
      if (isFeatureEnabled('SEAT_LIMIT_ENFORCEMENT')) {
        // Allow re-join / no-op if user is already in this org.
        const currentRes = await db.query(
          'SELECT organization_id FROM users WHERE id = $1',
          [userId]
        );
        const currentOrg = currentRes.rows[0]?.organization_id;
        if (currentOrg !== org.id) {
          const seatCheck = await canOrgAcceptNewMember(db, org.id);
          if (!seatCheck.ok) {
            return res.status(409).json({
              ok: false,
              error: seatCheck.reason,
              message:
                seatCheck.reason === 'seat_limit_reached'
                  ? `This organization is at its seat limit (${seatCheck.limit}). Please contact your administrator.`
                  : 'This organization is not accepting new members right now. Please contact your administrator.',
            });
          }
        }
      }

      // Validate access code if organization requires one
      if (org.access_code) {
        if (!access_code) {
          return res.status(400).json({
            ok: false,
            error: 'access_code_required',
            message: 'This organization requires an access code',
          });
        }

        if (access_code.trim() !== org.access_code) {
          return res.status(403).json({
            ok: false,
            error: 'invalid_access_code',
            message: 'The access code you entered is incorrect',
          });
        }
      }

      // Update user's organization. Also force account_status='active' and
      // clear any leftover pending_organization_id so the requireActiveAccount
      // gate stops blocking this user (otherwise they'd see "account
      // restricted" errors after picking an org).
      await db.query(
        `UPDATE users
         SET organization_id = $1,
             organization_join_code = $2,
             account_status = 'active',
             pending_organization_id = NULL
         WHERE id = $3`,
        [organization_id, access_code || null, userId]
      );

      // Reload user with fresh organization data
      const updatedUser = await loadUserWithRole(userId);

      return res.json({
        ok: true,
        user: buildUserResponse(updatedUser),
      });
    } catch (err) {
      console.error('[/api/student/select-organization] ERROR:', err);
      return res.status(500).json({
        ok: false,
        error: 'Failed to join organization',
        details: err?.message || String(err),
      });
    }
  }
);

