// Ask Coach advice endpoint with weekly throttle (2/week) and challenge selection requirement
app.post(
  '/api/coach/advice',
  devAuth,
  ensureTestUserForNow,
  requireAuthInProd,
  authRequired,
  express.json(),
  async (req, res) => {
    try {
      const userId = req.user.id;
      let email = (req.user && (req.user.email || req.user.userEmail)) || null;
      if (!email) {
        email = await getUserEmailById(userId);
      }

      const testerByEmail = false;

      // Build profile bundle to inspect selected challenges and test plan
      const bundle = await buildProfileBundle(userId);
      const challengeOptions = Array.isArray(bundle?.challengeOptions)
        ? bundle.challengeOptions
        : [];
      const selected = challengeOptions.filter((c) => c && c.selected);

      if (!Array.isArray(selected) || selected.length === 0) {
        return res.status(400).json({
          error:
            'Pick at least one challenge in your profile so Coach can tailor advice.',
        });
      }

      // Subject hint is optional; if provided, narrow the selected challenges
      const subjectHintRaw =
        req.body && req.body.subject ? String(req.body.subject) : '';
      const subjectHint = subjectHintRaw
        ? subjectHintRaw.toLowerCase() === 'rla'
          ? 'RLA'
          : subjectHintRaw.toLowerCase().startsWith('social')
            ? 'Social Studies'
            : subjectHintRaw.charAt(0).toUpperCase() + subjectHintRaw.slice(1)
        : '';

      const bySubject = subjectHint
        ? selected.filter((s) => (s.subject || '').toString() === subjectHint)
        : selected;

      // Throttle: 2 per week per user, unless tester email
      const weekStartISO = getCurrentWeekStartISO();
      if (!testerByEmail) {
        const existing = await db.oneOrNone(
          `SELECT used_count FROM coach_advice_usage WHERE user_id = $1 AND week_start_date = $2`,
          [userId, weekStartISO]
        );
        const used = existing?.used_count || 0;
        if (used >= 2) {
          return res.status(429).json({
            error:
              "You've reached your Ask Coach limit for this week (2/2). Try again next week.",
          });
        }
      }

      // Gather test date context for the hinted subject (or nearest upcoming)
      const testPlan = Array.isArray(bundle?.testPlan) ? bundle.testPlan : [];
      let subjectTestDate = '';
      if (subjectHint) {
        const match = testPlan.find(
          (t) => t && t.subject === subjectHint && t.testDate
        );
        subjectTestDate = match?.testDate || '';
      } else {
        const upcoming = testPlan.find((t) => t && t.testDate);
        subjectTestDate = upcoming?.testDate || '';
      }

      // Compose prompt for AI
      const tagList = bySubject
        .map((c) => `${c.subject}: ${c.subtopic} — ${c.label}`)
        .slice(0, 10)
        .join('\n- ');
      const subjForPrompt = subjectHint || 'your GED subjects';
      const dateForPrompt = subjectTestDate
        ? `Target test date: ${subjectTestDate}.`
        : 'No test date saved yet.';
      const prompt = `You are Coach Smith, a concise GED study coach.
Provide 3-5 specific, encouraging tips tailored to ${subjForPrompt}.
Focus on 45-minute sessions and include one quick practice idea.
Ground your advice in these selected challenges (if present):
- ${tagList || 'No tags selected beyond basics.'}
${dateForPrompt}
Return JSON as { "advice": "<single paragraph or short bullets>" }.`;

      const SCHEMA = {
        type: 'OBJECT',
        properties: { advice: { type: 'STRING' } },
        required: ['advice'],
      };

      let adviceText = '';
      try {
        const ai = await callAI(prompt, SCHEMA, {
          generationOverrides: { temperature: 0.7 },
        });
        adviceText = ai && ai.advice ? String(ai.advice) : '';
      } catch (e) {
        // Fallback to simple templated guidance
        const firstTag = bySubject[0] || selected[0];
        const tagStr = firstTag
          ? `${firstTag.subject}: ${firstTag.subtopic.toLowerCase()}`
          : 'your weakest areas';
        adviceText = `Spend 45 minutes today focused on ${tagStr}. Start with 10 minutes reviewing notes, then 25 minutes of practice (2-3 short passages or 8-10 problems), and finish with a 10-minute reflection to write down one mistake pattern and how you\'ll fix it next time.`;
        if (subjectTestDate) {
          adviceText += ` You\'ve saved a test date (${subjectTestDate}) — aim for 3 focused sessions this week.`;
        }
      }

      // Record usage (skip for tester email)
      if (!testerByEmail) {
        await db.query(
          `INSERT INTO coach_advice_usage (user_id, week_start_date, used_count, last_used_at)
                 VALUES ($1, $2, 1, now())
                 ON CONFLICT (user_id, week_start_date)
                 DO UPDATE SET used_count = coach_advice_usage.used_count + 1, last_used_at = now()`,
          [userId, weekStartISO]
        );
      }

      return res.json({
        ok: true,
        advice: adviceText,
        weekStart: weekStartISO,
      });
    } catch (e) {
      console.error('POST /api/coach/advice failed:', e?.message || e);
      return res
        .status(500)
        .json({ error: 'Unable to fetch advice right now.' });
    }
  }
);

/* ──────────────────────────────────────────────────────────
   Coach Chat – persistent multi-turn conversation
   ────────────────────────────────────────────────────────── */

const COACH_CHAT_DAILY_LIMIT = 30;

function buildCoachSystemPrompt(ctx) {
  const {
    domainMastery,
    weakestAreas,
    confidenceData,
    scoreTrends,
    recentAttempts,
    selectedChallenges,
    testPlan,
    subjectStatus,
    totalQuizzes,
    totalQuestions,
  } = ctx;

  const weakStr = weakestAreas.length
    ? weakestAreas
        .map(
          (w) =>
            `  • ${w.subject}/${w.domain || w.topic}: ${w.accuracy_pct}% (${w.correct}/${w.total})`
        )
        .join('\n')
    : '  No data yet.';

  const trendStr = Object.entries(scoreTrends).length
    ? Object.entries(scoreTrends)
        .map(
          ([s, t]) =>
            `  • ${s}: latest ${t.latest}, best ${t.best}, growth ${t.growth >= 0 ? '+' : ''}${t.growth}, ${t.attemptCount} attempts, ${t.passCount} passed`
        )
        .join('\n')
    : '  No scores yet.';

  const recentStr = recentAttempts.length
    ? recentAttempts
        .map(
          (a) =>
            `  • ${a.subject} "${a.quiz_title}": ${a.score}/${a.total_questions} (scaled ${a.scaled_score}) ${a.passed ? '✓PASS' : '✗FAIL'}`
        )
        .join('\n')
    : '  No recent quizzes.';

  const calStr =
    confidenceData.calibrationScore != null
      ? `Calibration score: ${confidenceData.calibrationScore}/100 (100 = perfectly calibrated confidence vs. actual performance).`
      : 'Not enough confidence data yet.';

  const testDateStr = testPlan.length
    ? testPlan
        .map(
          (t) =>
            `  • ${t.subject}: ${t.testDate || 'no date'} (${t.daysUntil != null ? t.daysUntil + ' days' : '?'})`
        )
        .join('\n')
    : '  No test dates saved.';

  const passedSubjects = Object.entries(subjectStatus)
    .filter(([, p]) => p)
    .map(([s]) => s);
  const passedStr = passedSubjects.length
    ? passedSubjects.join(', ')
    : 'none yet';

  return `You are Coach Smith, an expert GED tutor and study coach.

PERSONALITY:
- Warm, encouraging, and direct. Use a conversational tone.
- Celebrate progress, no matter how small.
- When the student struggles, be empathetic but solution-oriented.
- Keep responses concise (1-3 short paragraphs unless the student asks for a detailed explanation).
- Use simple language at a high-school level. Avoid jargon.

GED KNOWLEDGE:
- The GED has 4 subjects: Math, Science, Social Studies, and RLA (Reasoning Through Language Arts).
- Passing score is 145 per subject (out of 200). 145-164 = Pass, 165-174 = College Ready, 175+ = College Ready + Credit.
- You know the content areas, question types, and test strategies for each subject.

THE STUDENT'S DATA (use this to personalize every response):
Overall: ${totalQuizzes} quizzes taken, ${totalQuestions} questions answered.
Subjects passed: ${passedStr}.

Score Trends:
${trendStr}

Recent Quizzes:
${recentStr}

Weakest Areas:
${weakStr}

Confidence Calibration:
${calStr}

Test Dates:
${testDateStr}

RULES:
- Always ground your advice in the student's actual data above.
- If they ask "what should I study?", reference their weakest areas and upcoming test dates.
- If they ask about a concept, explain it clearly with an example.
- Never fabricate scores or data. If data is missing, say so and encourage them to take more quizzes.
- Do NOT use markdown headers (#). Use plain text with occasional bold (**word**) for emphasis.
- If asked something unrelated to GED prep or studying, gently redirect.`;
}

// POST /api/coach/chat – send a message, get AI reply
app.post(
  '/api/coach/chat',
  devAuth,
  ensureTestUserForNow,
  requireAuthInProd,
  authRequired,
  express.json(),
  async (req, res) => {
    try {
      const userId = req.user?.id || req.user?.userId;
      if (!userId) return res.status(401).json({ error: 'Not authenticated' });

      const userMessage = (req.body?.message || '').trim();
      if (!userMessage || userMessage.length > 2000) {
        return res
          .status(400)
          .json({ error: 'Message is required (max 2000 chars).' });
      }

      // Rate limit: 30 messages per day
      const todayStart = todayISO();
      const countRes = await pool.query(
        `SELECT COUNT(*)::int AS cnt FROM coach_conversations
         WHERE user_id = $1 AND role = 'user' AND created_at >= $2::date`,
        [userId, todayStart]
      );
      if ((countRes.rows[0]?.cnt || 0) >= COACH_CHAT_DAILY_LIMIT) {
        return res.status(429).json({
          error: `You've reached your daily chat limit (${COACH_CHAT_DAILY_LIMIT} messages). Come back tomorrow!`,
        });
      }

      // Load last 20 messages for context window
      const historyRes = await pool.query(
        `SELECT role, content FROM coach_conversations
         WHERE user_id = $1 ORDER BY created_at DESC LIMIT 20`,
        [userId]
      );
      const history = historyRes.rows.reverse();

      // Build rich context
      const ctx = await buildCoachContext(userId);
      const systemPrompt = buildCoachSystemPrompt(ctx);

      // Format messages for Gemini
      const geminiMessages = [];
      for (const msg of history) {
        geminiMessages.push({
          role: msg.role === 'assistant' ? 'model' : 'user',
          text: msg.content,
        });
      }
      // Append the new user message
      geminiMessages.push({ role: 'user', text: userMessage });

      // Call AI
      const aiResponse = await callCoachChat(systemPrompt, geminiMessages, {
        temperature: 0.7,
      });

      // Store user message + AI response
      await pool.query(
        `INSERT INTO coach_conversations (user_id, role, content) VALUES ($1, 'user', $2)`,
        [userId, userMessage]
      );
      const insertRes = await pool.query(
        `INSERT INTO coach_conversations (user_id, role, content) VALUES ($1, 'assistant', $2) RETURNING id`,
        [userId, aiResponse]
      );

      return res.json({
        ok: true,
        message: aiResponse,
        messageId: insertRes.rows[0]?.id,
      });
    } catch (e) {
      console.error('POST /api/coach/chat failed:', e?.message || e);
      return res
        .status(500)
        .json({ error: 'Coach is unavailable right now. Try again shortly.' });
    }
  }
);

