function repairIllegalJsonEscapes(s) {
  if (typeof s !== 'string') return s;
  return s.replace(/\\(?!["\\\/bfnrtu])/g, '\\\\');
}

function recoverTruncatedJsonArray(s) {
  if (typeof s !== 'string') return null;
  const text = s.trim();
  if (!text.startsWith('[')) return null;

  const lastObjectEnd = text.lastIndexOf('}');
  if (lastObjectEnd === -1) return null;

  let candidate = text.slice(0, lastObjectEnd + 1).trim();
  candidate = candidate.replace(/,\s*$/, '');
  candidate = `${candidate}]`;

  try {
    const parsed = JSON.parse(candidate);
    return Array.isArray(parsed) ? parsed : null;
  } catch {
    return null;
  }
}

function sanitizeAiJsonValue(value) {
  if (Array.isArray(value)) {
    return value.map((item) => sanitizeAiJsonValue(item));
  }
  if (!value || typeof value !== 'object') {
    return value;
  }

  const cleaned = {};
  for (const [key, raw] of Object.entries(value)) {
    if (typeof raw === 'string' && raw.length > 5000) {
      continue;
    }
    cleaned[key] = sanitizeAiJsonValue(raw);
  }
  return cleaned;
}

const callAI = async (prompt, schema, options = {}) => {
  const apiKey = process.env.GOOGLE_AI_API_KEY || process.env.GOOGLE_API_KEY;
  if (!apiKey) {
    console.error('API key not configured on the server.');
    throw new Error(
      'Server configuration error: GOOGLE_AI_API_KEY or GOOGLE_API_KEY is not set.'
    );
  }
  const apiUrl = `https://generativelanguage.googleapis.com/v1beta/models/gemini-2.5-flash:generateContent?key=${apiKey}`;
  const {
    parser,
    onParserMetadata,
    generationOverrides,
    fileSearchConfig,
    timeoutMs,
    signal,
  } = options;
  const payload = {
    contents: [{ parts: [{ text: prompt }] }],
    generationConfig: {
      responseMimeType: 'application/json',
      responseSchema: schema,
      ...(generationOverrides || {}),
    },
  };
  // Optional Gemini File Search support (adds retrieval tools while keeping structured output)
  if (fileSearchConfig) {
    // tell Gemini that we want to use the file_search tool
    payload.tools = [
      {
        file_search: {},
      },
    ];
    // pass in the store / filters / max results
    payload.tool_config = {
      file_search: {
        ...fileSearchConfig,
      },
    };
  }
  try {
    const requestConfig = {};
    if (timeoutMs) {
      requestConfig.timeout = timeoutMs;
    }
    if (signal) {
      requestConfig.signal = signal;
    }

    const response = await http.post(apiUrl, payload, requestConfig);
    const rawText = response.data.candidates?.[0]?.content?.parts?.[0]?.text;

    if (typeof rawText !== 'string') {
      throw new Error('AI response did not include text content.');
    }

    const cleanedText = rawText
      .replace(/```json/g, '')
      .replace(/```/g, '')
      .trim();

    if (typeof parser === 'function') {
      const parsedResult = parser(cleanedText);
      if (
        parsedResult &&
        typeof parsedResult === 'object' &&
        Object.prototype.hasOwnProperty.call(parsedResult, 'value')
      ) {
        onParserMetadata?.(parsedResult);
        return parsedResult.value;
      }
      onParserMetadata?.({ stage: 'custom-parser' });
      return parsedResult;
    }

    try {
      return sanitizeAiJsonValue(JSON.parse(cleanedText));
    } catch (initialParseError) {
      const repairedText = repairIllegalJsonEscapes(cleanedText);
      try {
        const parsed = JSON.parse(repairedText);
        console.warn(
          'Successfully repaired AI JSON response after initial parse failure.'
        );
        return sanitizeAiJsonValue(parsed);
      } catch (reparseError) {
        const recoveredArray = recoverTruncatedJsonArray(repairedText);
        if (recoveredArray) {
          console.warn(
            `Recovered ${recoveredArray.length} AI items from truncated JSON response.`
          );
          return sanitizeAiJsonValue(recoveredArray);
        }
        const snippet = repairedText.slice(0, 5000);
        console.error(
          'Failed to parse AI JSON response after repair attempt.',
          {
            initialError: initialParseError.message,
            repairError: reparseError.message,
            snippet,
          }
        );
        throw reparseError;
      }
    }
  } catch (error) {
    console.error(
      'Error calling Google AI API in callAI:',
      error.response ? error.response.data : error.message
    );
    throw error;
  }
};

/**
 * callCoachChat – multi-turn Gemini chat for Coach Smith.
 * @param {string} systemInstruction - system prompt
 * @param {{role:'user'|'model', text:string}[]} messages - ordered conversation
 * @param {object} [opts] - { temperature }
 * @returns {Promise<string>} plain-text assistant response
 */
const callCoachChat = async (systemInstruction, messages, opts = {}) => {
  const apiKey = process.env.GOOGLE_AI_API_KEY || process.env.GOOGLE_API_KEY;
  if (!apiKey)
    throw new Error('GOOGLE_AI_API_KEY or GOOGLE_API_KEY is not set.');
  const apiUrl = `https://generativelanguage.googleapis.com/v1beta/models/gemini-2.5-flash:generateContent?key=${apiKey}`;
  const contents = messages.map((m) => ({
    role: m.role, // 'user' or 'model'
    parts: [{ text: m.text }],
  }));
  const payload = {
    systemInstruction: { parts: [{ text: systemInstruction }] },
    contents,
    generationConfig: {
      temperature: opts.temperature ?? 0.7,
      maxOutputTokens: 2048,
    },
  };
  const response = await http.post(apiUrl, payload, { timeout: 30000 });
  const raw = response.data.candidates?.[0]?.content?.parts?.[0]?.text;
  if (typeof raw !== 'string') throw new Error('Coach AI returned no text.');
  return raw.trim();
};

async function callMathValidator(payload) {
  if (!MATH_TWO_PASS_ENABLED) {
    return [];
  }

  const system = payload?.system || VALIDATOR_SYSTEM_PROMPT;
  const user = payload?.user || VALIDATOR_USER_PROMPT;
  const prompt = `SYSTEM:\n${system}\n\nUSER:\n${user}`;

  try {
    return await callAI(prompt, MATH_VALIDATOR_SCHEMA, {
      generationOverrides: { temperature: 0.2 },
    });
  } catch (error) {
    console.error(
      'Math validator call failed; continuing with auto-fixed text.',
      error.message || error
    );
    return [];
  }
}

async function runMathTwoPassOnQuestions(questions, subject) {
  if (!MATH_TWO_PASS_ENABLED) {
    return;
  }

  if (!Array.isArray(questions) || !questions.length) {
    return;
  }

  const exam = {
    subject: subject || '',
    questions: [],
  };

  const questionMap = new Map();

  questions.forEach((question, index) => {
    if (!question || typeof question !== 'object') {
      return;
    }

    const qid = String(
      question.id != null
        ? question.id
        : question.questionNumber != null
          ? question.questionNumber
          : `math-${index}`
    );

    const choiceMap = new Map();
    const choices = Array.isArray(question.answerOptions)
      ? question.answerOptions.map((opt, idx) => {
          const choiceId = String(opt && opt.id != null ? opt.id : idx);
          if (opt) {
            choiceMap.set(choiceId, opt);
          }
          return {
            id: choiceId,
            text: typeof (opt && opt.text) === 'string' ? opt.text : '',
          };
        })
      : [];

    questionMap.set(qid, {
      original: question,
      choices: choiceMap,
    });

    exam.questions.push({
      id: qid,
      stem:
        typeof question.questionText === 'string' ? question.questionText : '',
      choices,
      explanation:
        typeof question.rationale === 'string' ? question.rationale : undefined,
    });
  });

  if (!exam.questions.length) {
    return;
  }

  const processed = await generateMathExamTwoPass(
    () => Promise.resolve(exam),
    callMathValidator
  );

  if (!processed || !Array.isArray(processed.questions)) {
    return;
  }

  processed.questions.forEach((processedQuestion) => {
    const entry = questionMap.get(String(processedQuestion.id));
    if (!entry) {
      return;
    }

    const { original, choices } = entry;

    if (typeof processedQuestion.stem === 'string') {
      original.questionText = processedQuestion.stem;
    }

    if (Array.isArray(processedQuestion.choices)) {
      processedQuestion.choices.forEach((choice) => {
        const target = choices.get(String(choice.id));
        if (target && typeof choice.text === 'string') {
          target.text = choice.text;
        }
      });
    }

    if (typeof processedQuestion.explanation === 'string') {
      if (original.rationale !== undefined) {
        original.rationale = processedQuestion.explanation;
      } else if (processedQuestion.explanation.length) {
        original.rationale = processedQuestion.explanation;
      }
    }
  });
}

// ============================================================
// SOCIAL STUDIES HELPERS
// ============================================================

function getCuratedSocialStudiesPassages(PASSAGE_DB) {
  const node =
    PASSAGE_DB && (PASSAGE_DB['Social Studies'] || PASSAGE_DB.social_studies);
  if (!node) return [];

  const items = Array.isArray(node) ? node : node.passages || [];
  return items.filter(Boolean);
}

function getCuratedSocialStudiesImages(imageCatalog) {
  if (!imageCatalog || typeof imageCatalog !== 'object') return [];
  return Object.values(imageCatalog).filter((img) => {
    // Skip entries explicitly marked as non-existent
    if (img.__exists === false) return false;

    const keywords = Array.isArray(img.keywords)
      ? img.keywords.map((t) => String(t).toLowerCase())
      : [];
    const subject = (img.subject || '').toLowerCase();
    return (
      subject.includes('social') ||
      keywords.includes('social_studies') ||
      keywords.includes('civics') ||
      keywords.includes('history') ||
      keywords.includes('economics') ||
      keywords.includes('geography') ||
      keywords.includes('political_cartoon')
    );
  });
}

function getImageOverlayEntry(bank, img) {
  if (!img?.filePath || !bank || typeof bank !== 'object') return null;
  for (const alias of getImagePathAliases(img.filePath)) {
    if (bank[alias]) return bank[alias];
  }
  return null;
}

function getSocialStudiesImageBankEntry(img) {
  return getImageOverlayEntry(SOCIAL_STUDIES_IMAGE_QUESTION_BANK, img);
}

function getSocialStudiesImageQuestionSetEntry(img) {
  return getImageOverlayEntry(SOCIAL_STUDIES_IMAGE_QUESTION_SETS, img);
}

