// ------------------------------------------------------------
// Stimulus-aware grouping & shuffling helpers
// ------------------------------------------------------------
function groupQuestionsByStimulus(questions) {
  if (!Array.isArray(questions)) return [];
  const groups = [];
  const keyToGroupIdx = new Map();
  questions.forEach((q) => {
    if (!q) return;
    let key = null;
    if (q.stimulusId) key = `stim:${q.stimulusId}`;
    else if (typeof q.passage === 'string') {
      const p = q.passage;
      if (p && p.trim().length) key = `pass:${p.trim()}`;
    } else if (q.imageId) key = `img:${q.imageId}`;
    else if (q.image) key = `img:${q.image}`;
    if (key) {
      if (keyToGroupIdx.has(key)) {
        groups[keyToGroupIdx.get(key)].push(q);
      } else {
        const idx = groups.length;
        keyToGroupIdx.set(key, idx);
        groups.push([q]);
      }
    } else {
      groups.push([q]);
    }
  });
  return groups;
}

function shuffleQuestionsPreservingStimulus(questions) {
  const groups = groupQuestionsByStimulus(questions);
  shuffleArray(groups); // existing shuffleArray already defined earlier
  const flattened = [];
  for (const g of groups) for (const q of g) flattened.push(q);
  return flattened;
}

// Science table stimulus helper for data-based questions
// Science table stimulus functions removed - AI now generates tables dynamically

function scoreImageForTopic(img, subject, topic) {
  if (!img || img.__exists === false) return -1;

  const subjectLc = norm(subject);
  const topicLc = norm(topic);
  const tokenBag = imageTokenBag(img);
  const topicLcTokens = topicTokens(topic);
  const categoryLc = norm(img.category);
  const subjectFields = [img.subject, ...(img.subjectAreas || [])]
    .map((value) => norm(value))
    .filter(Boolean)
    .join(' ');

  if (subjectLc && !subjectFields.includes(subjectLc)) {
    return 0;
  }

  let score = subjectLc ? 50 : 0;

  if (topicLc && categoryLc === topicLc) {
    score += 45;
  } else if (
    topicLc &&
    categoryLc &&
    (categoryLc.includes(topicLc) || topicLc.includes(categoryLc))
  ) {
    score += 30;
  }

  for (const token of topicLcTokens) {
    if (tokenBag.has(token)) {
      score += token.length >= 7 ? 9 : 6;
    }
  }

  const topicalLists = [
    ...(Array.isArray(img.topicTags) ? img.topicTags : []),
    ...(Array.isArray(img.relatedSkills) ? img.relatedSkills : []),
    ...(Array.isArray(img.reasoningModes) ? img.reasoningModes : []),
    ...(Array.isArray(img.stimulusTypes) ? img.stimulusTypes : []),
  ]
    .map((value) => norm(value))
    .filter(Boolean);

  if (topicLc && topicalLists.some((value) => value === topicLc)) {
    score += 20;
  } else if (topicLc && topicalLists.some((value) => value.includes(topicLc))) {
    score += 12;
  }

  const questionSeeds = getImageQuestionSeeds(img);
  if (questionSeeds.length) score += Math.min(10, questionSeeds.length * 2);
  if (getImageUsageDirectives(img)) score += 4;

  const groundingStrength = Number(img.__groundingStrength || 0);
  if (groundingStrength > 0) score += Math.min(12, groundingStrength);

  const qualityRank = Number(img.qualityRank || 0);
  if (Number.isFinite(qualityRank) && qualityRank > 0) {
    score += Math.max(0, 8 - Math.min(7, qualityRank - 1));
  }

  return score;
}

// NEW version – smarter image selection with cartoon support and reuse prevention
const generateImageQuestion = async (
  topic,
  subject,
  imagePool,
  numQuestions,
  options = {}
) => {
  const { usedImages = new Set(), mustBeCartoon = false } = options;

  // start from the pool we were given
  let pool = Array.isArray(imagePool) ? imagePool : [];

  // if the caller wants a cartoon, narrow to cartoon-like images
  if (mustBeCartoon) {
    const CARTOON_RE = /cartoon|political cartoon|satire|caricature/i;
    pool = pool.filter((img) => {
      const bag = [
        img.category,
        img.altText,
        img.detailedDescription,
        Array.isArray(img.keywords) ? img.keywords.join(' ') : '',
      ]
        .filter(Boolean)
        .join(' ')
        .toLowerCase();
      return CARTOON_RE.test(bag);
    });
  }

  // score for subject/topic and skip images already used in this run
  const scored = (pool || [])
    .map((img) => ({
      img,
      score: scoreImageForTopic(img, subject, topic),
    }))
    .filter(
      (x) => x.score > 0 && !(x.img.filePath && usedImages.has(x.img.filePath))
    )
    .sort((a, b) => b.score - a.score);

  if (!scored.length) {
    console.warn(
      `[AI-IMG] No image match for subject=${subject}, topic=${topic}, mustBeCartoon=${mustBeCartoon}`
    );
    return null;
  }

  // Weighted random across a wider candidate window so comprehensive exams
  // draw from a vast array of images, not the same top 1–2.
  const TOP_K = Math.min(24, scored.length);
  const candidates = scored.slice(0, TOP_K);
  // Soft weights: rank 1 → weight K, rank K → weight 1. Keeps high-scoring
  // images preferred without monopolizing the selection.
  const weights = candidates.map((_, i) => TOP_K - i);
  const totalWeight = weights.reduce((s, w) => s + w, 0);
  let r = Math.random() * totalWeight;
  let pickIdx = 0;
  for (let i = 0; i < weights.length; i++) {
    r -= weights[i];
    if (r <= 0) {
      pickIdx = i;
      break;
    }
  }
  const pick = candidates[pickIdx].img;

  // remember it for this quiz
  if (pick.filePath) {
    usedImages.add(pick.filePath);
  }

  const imagePrompt = `
You are creating GED-level ${subject} questions that require students to interpret an image.
You are given an image record from our database:
${JSON.stringify(
  {
    subject: pick.subject,
    filePath: pick.filePath,
    altText: pick.altText,
    detailedDescription: pick.detailedDescription,
    extractedText: trimImageContextText(pick.extractedText || '', 220),
    category: pick.category,
    keywords: normalizeImageStringList(pick.keywords).slice(0, 8),
    questionSeeds: getImageQuestionSeeds(pick).slice(0, 4),
    usageDirectives: getImageUsageDirectives(pick),
    subjectAreas: normalizeImageStringList(pick.subjectAreas).slice(0, 4),
    topicTags: normalizeImageStringList(pick.topicTags).slice(0, 6),
    stimulusTypes: normalizeImageStringList(pick.stimulusTypes).slice(0, 4),
    qualityRank: pick.qualityRank || null,
    groundingStrength: pick.__groundingStrength || 0,
  },
  null,
  2
)}
Based ONLY on THIS image and staying within the subject "${subject}" and topic "${topic}", create ${numQuestions} multiple-choice questions.

QUALITY BAR — write SUBSTANTIVE, GED-level questions, not trivia identification:
- Each question stem must be at least 2 sentences (or 1 long sentence + a clause). Set a brief context, then ask the analytical question.
- At least one of the ${numQuestions} questions MUST go beyond simple identification — it should ask about cause, effect, significance, comparison, change over time, motivation, or what the image SUGGESTS or IMPLIES.
- Avoid one-line "What is shown?" / "What does the map show?" / "What does the chart depict?" stems. Treat the image as evidence the student must reason from.
- For maps: ask about historical/geographic significance, spatial relationships between labeled features, or what the highlighted region tells us about a broader event (e.g., territorial expansion, migration, conflict).
- For political cartoons: ask about the cartoonist's argument, the symbolism of specific labeled elements, the historical event being satirized, or whose perspective is represented — not just "what is shown."
- For data charts/graphs: ask about trends, comparisons between data points, what the data supports or refutes, or what additional information would be needed to draw a conclusion.
- For diagrams: ask about the process represented, what would change if a labeled component were removed/altered, or how the parts work together.
- Each distractor must be a plausible misreading of the image, not obviously absurd. Each rationale must explain WHY the option is right or wrong with reference to the image.
- Reference or rely on the image in every question.

If questionSeeds or usageDirectives are present, stay within those approved angles.
Do not invent any label, value, region, date, scientific relationship, or symbolic meaning that is not explicitly supported by the image record.
Return valid JSON only.
`;

  const imageQuestionSchema = {
    type: 'ARRAY',
    items: {
      type: 'OBJECT',
      properties: {
        questionText: { type: 'STRING' },
        answerOptions: {
          type: 'ARRAY',
          items: {
            type: 'OBJECT',
            properties: {
              text: { type: 'STRING' },
              isCorrect: { type: 'BOOLEAN' },
              rationale: { type: 'STRING' },
            },
            required: ['text', 'isCorrect', 'rationale'],
          },
        },
        stimulusImage: {
          type: 'OBJECT',
          properties: {
            src: { type: 'STRING' },
            alt: { type: 'STRING' },
          },
          required: ['src'],
        },
      },
      required: ['questionText', 'answerOptions'],
    },
  };

  try {
    const aiRes = await callAI(imagePrompt, imageQuestionSchema, options);

    return (Array.isArray(aiRes) ? aiRes : []).map((q) => ({
      ...q,
      itemType: 'image',
      stimulusImage: {
        src: pick.filePath,
        alt: pick.altText || '',
      },
    }));
  } catch (error) {
    console.error(`Error generating image question for topic ${topic}:`, error);
    return null;
  }
};

