      const { rows } = await db.query(
        `SELECT u.id, u.name, u.email, e.enrolled_at
           FROM class_enrollments e
           JOIN users u ON u.id = e.user_id
          WHERE e.class_id = $1
          ORDER BY u.name NULLS LAST, u.email`,
        [classId]
      );
      return res.json({ members: rows });
