// Load quizzes from dynamic index which merges legacy and supplemental topics
// Moved to top of file to ensure availability for adaptive logic
// const { ALL_QUIZZES } = require('./data/quizzes/index.js');

// Subtopic → challenge tag mapping for auto-derivation when questions lack explicit tags
const SUBTOPIC_TO_CHALLENGE = {
  Fractions: ['math:fraction'],
  Decimals: ['math:decimals'],
  'Ratios, Proportions & Percents': ['math:ratio-percent'],
  'Scientific Numeracy': ['science:numeracy'],
  'Reading for Meaning': ['rla:inference'],
  'Main Idea': ['rla:main-idea'],
};

function deriveTagsFromContext(subjectKey, categoryName, topic) {
  // Prefer topic title mapping first
  const tTitle =
    topic && (topic.title || topic.id) ? String(topic.title || topic.id) : '';
  if (tTitle && SUBTOPIC_TO_CHALLENGE[tTitle])
    return SUBTOPIC_TO_CHALLENGE[tTitle];
  // Fallback to category mapping
  const cName = categoryName ? String(categoryName) : '';
  if (cName && SUBTOPIC_TO_CHALLENGE[cName])
    return SUBTOPIC_TO_CHALLENGE[cName];
  return [];
}

function normalizeLearnerQuestionTier(raw) {
  const t = String(raw || '')
    .trim()
    .toLowerCase();
  if (!t) return null;
  if (t === 'foundation' || t === 'test-ready' || t === 'challenge') return t;
  if (t === 'foundations' || t === 'core') return 'foundation';
  return null;
}

function inferTopicLearnerTier(topic) {
  const topicTier = normalizeLearnerQuestionTier(topic?.tier);
  if (topicTier) return topicTier;

  const topicId = String(topic?.id || '')
    .trim()
    .toLowerCase();
  if (!topicId) return 'foundation';
  if (/set4|_10$|_11$|_12$|challenge/.test(topicId)) return 'challenge';
  if (/set3|_07$|_08$|_09$|test-ready/.test(topicId)) return 'test-ready';
  return 'foundation';
}

function inferQuestionLearnerTier(question, topic) {
  const explicit = normalizeLearnerQuestionTier(
    question?.tier || question?.questionTier || question?.level
  );
  if (explicit) return explicit;

  const diff = String(question?.difficulty || '')
    .trim()
    .toLowerCase();
  if (diff === 'hard') return 'challenge';
  if (diff === 'medium') return 'test-ready';
  if (diff === 'easy') return 'foundation';

  return inferTopicLearnerTier(topic);
}

function estimateQuestionComplexityScore(question) {
  const tier = normalizeLearnerQuestionTier(question?.tier);
  const tierWeight = tier === 'challenge' ? 3 : tier === 'test-ready' ? 2 : 1;

  const difficulty = String(question?.difficulty || '')
    .trim()
    .toLowerCase();
  const difficultyWeight =
    difficulty === 'hard' ? 3 : difficulty === 'medium' ? 2 : 1;

  const prompt = String(
    question?.question ||
      question?.questionText ||
      question?.content?.questionText ||
      ''
  ).toLowerCase();
  const passage = String(
    question?.passage || question?.content?.passage || ''
  ).toLowerCase();

  let reasoningCueScore = 0;
  if (
    /\b(analyze|evaluate|justify|best\s+supports|most\s+likely|infer|evidence)\b/.test(
      `${prompt} ${passage}`
    )
  ) {
    reasoningCueScore += 1;
  }
  if (
    /\b(first|then|after|compare|contrast|step|multi-step|based\s+on)\b/.test(
      prompt
    )
  ) {
    reasoningCueScore += 1;
  }

  const optionCount = Array.isArray(question?.answerOptions)
    ? question.answerOptions.length
    : 0;
  if (optionCount >= 5) reasoningCueScore += 0.5;
  if (passage.length > 220) reasoningCueScore += 1;
  if (prompt.length > 180) reasoningCueScore += 0.5;

  return tierWeight * 100 + difficultyWeight * 25 + reasoningCueScore * 10;
}

function orderQuestionsForTierTarget(questions, targetTierRaw) {
  const targetTier = normalizeLearnerQuestionTier(targetTierRaw);
  const list = Array.isArray(questions) ? questions.slice() : [];
  if (!list.length) return list;
  if (!targetTier) return shuffleArray(list);

  const scored = shuffleArray(list).map((q) => ({
    question: q,
    score: estimateQuestionComplexityScore(q),
  }));

  if (targetTier === 'foundation') {
    scored.sort((a, b) => a.score - b.score);
  } else if (targetTier === 'challenge') {
    scored.sort((a, b) => b.score - a.score);
  } else {
    const targetScore = 240;
    scored.sort((a, b) => {
      const aPenalty = a.score < 170 ? 80 : 0;
      const bPenalty = b.score < 170 ? 80 : 0;
      return (
        Math.abs(a.score - targetScore) +
        aPenalty -
        (Math.abs(b.score - targetScore) + bPenalty)
      );
    });
  }

  return scored.map((row) => row.question);
}

function extractConciseImageDescription(rawText) {
  if (typeof rawText !== 'string') return rawText;
  const text = rawText.replace(/\r/g, '').trim();
  if (!text) return rawText;

  const hasVerboseMarkers = /(Alt text:|Description:|Text in image:)/i.test(
    text
  );
  if (!hasVerboseMarkers) return rawText;

  const pickSection = (label, input) => {
    const pattern = new RegExp(
      `${label}\\s*([\\s\\S]*?)(?:\\n\\s*\\n(?:Alt text:|Description:|Text in image:)|$)`,
      'i'
    );
    const match = input.match(pattern);
    return match && match[1] ? match[1].trim() : '';
  };

  let concise =
    pickSection('Alt text:', text) ||
    pickSection('Description:', text) ||
    text.split(/\n\s*\n/)[0] ||
    '';

  concise = concise
    .replace(/\s+/g, ' ')
    .replace(/[\u2026]+/g, '')
    .trim();

  if (concise.length > 220) {
    concise = `${concise.slice(0, 217).trimEnd()}...`;
  }

  return concise
    ? `Image description: ${concise}`
    : 'Image description: Refer to the image to answer the question.';
}

function sanitizeImageQuestionPassage(question) {
  if (!question || typeof question !== 'object') return question;

  const content =
    question.content && typeof question.content === 'object'
      ? question.content
      : null;

  const looksImageBased = Boolean(
    question.imageUrl ||
    question.imageURL ||
    question.image ||
    question.graphic ||
    (question.stimulusImage &&
      (typeof question.stimulusImage === 'string' ||
        question.stimulusImage.src)) ||
    (content && (content.imageURL || content.imageUrl || content.image)) ||
    /<img\b/i.test(String(question.passage || '')) ||
    /<img\b/i.test(String(content?.passage || ''))
  );

  if (!looksImageBased) return question;

  if (typeof question.passage === 'string') {
    question.passage = extractConciseImageDescription(question.passage);
  }
  if (content && typeof content.passage === 'string') {
    content.passage = extractConciseImageDescription(content.passage);
  }

  return question;
}

function ensureQuestionTags(
  subjectKey,
  categoryName,
  topic,
  question,
  idxForLog = null
) {
  try {
    sanitizeImageQuestionPassage(question);

    // Always attach lightweight source metadata for traceability
    try {
      const topicId = topic?.id || topic?.title || 'topic';
      const topicTitle = topic?.title || topic?.id || null;
      if (!question.sourceMeta) question.sourceMeta = {};
      if (!question.sourceMeta.subject)
        question.sourceMeta.subject = subjectKey;
      if (!question.sourceMeta.category)
        question.sourceMeta.category = categoryName || null;
      if (!question.sourceMeta.topicId)
        question.sourceMeta.topicId = topicId || null;
      if (!question.sourceMeta.topicTitle)
        question.sourceMeta.topicTitle = topicTitle || null;
      if (
        !question.sourceMeta.questionNumber &&
        typeof question.questionNumber === 'number'
      ) {
        question.sourceMeta.questionNumber = question.questionNumber;
      }
    } catch (_) {}

    // Ensure learner-facing question tier exists for progression filtering.
    try {
      if (!normalizeLearnerQuestionTier(question?.tier)) {
        question.tier = inferQuestionLearnerTier(question, topic);
      }
    } catch (_) {}

    const hasExplicit =
      Array.isArray(question?.challenge_tags) &&
      question.challenge_tags.length > 0;
    if (hasExplicit) {
      // Respect explicit tags
      return question;
    }
    const derived = deriveTagsFromContext(subjectKey, categoryName, topic);
    if (Array.isArray(derived) && derived.length > 0) {
      question.challenge_tags = derived.slice();
      return question;
    }
    // Log missing tag for later hand-tagging
    const topicId = topic?.id || topic?.title || 'topic';
    const qIndex = idxForLog != null ? `#${idxForLog + 1}` : '';
    if (process.env.NODE_ENV !== 'production') {
      console.warn(
        `[challenge-tags] question ${subjectKey}/${topicId}${qIndex} has no challenge_tags and no subtopic mapping`
      );
    }
    return question;
  } catch (e) {
    return question;
  }
}

// Expose ALL_QUIZZES for the frontend to build a unified catalog, including supplemental topics
function chunkInto3(list = []) {
  const out = [];
  for (let i = 0; i < list.length; i += 3) {
    const slice = list.slice(i, i + 3);
    out.push({ title: `Set ${out.length + 1}`, quizzes: slice });
  }
  return out;
}

function buildAllQuizzesWithTags(allQuizzes = ALL_QUIZZES) {
  // Deep-ish clone with tag normalization; keep structure intact
  const out = {};
  for (const [subjectKey, subj] of Object.entries(allQuizzes || {})) {
    const subjCopy = { icon: subj.icon || null, categories: {} };
    for (const [catName, cat] of Object.entries(subj.categories || {})) {
      const catCopy = { description: cat.description || '', topics: [] };
      const flatQuizzesForCategory = [];
      const topics = Array.isArray(cat.topics) ? cat.topics : [];
      topics.forEach((topic) => {
        const tCopy = { ...topic };
        // Normalize topic-level questions
        if (Array.isArray(topic.questions)) {
          const normalizedQuestions = topic.questions.map((q, i) => {
            const cloned = q && typeof q === 'object' ? { ...q } : q;
            return ensureQuestionTags(subjectKey, catName, topic, cloned, i);
          });
          const topicTier = inferTopicLearnerTier(topic);
          tCopy.questions = orderQuestionsForTierTarget(
            normalizedQuestions,
            topicTier
          );
        }
        // Preserve quizzes array if present and derive topic-level quizSets of 3
        if (Array.isArray(topic.quizzes)) {
          tCopy.quizzes = topic.quizzes.map((q) => {
            if (!q || typeof q !== 'object') return q;
            const quizCopy = { ...q };
            if (Array.isArray(quizCopy.questions)) {
              quizCopy.questions = quizCopy.questions.map((question, i) => {
                const cloned =
                  question && typeof question === 'object'
                    ? { ...question }
                    : question;
                return ensureQuestionTags(
                  subjectKey,
                  catName,
                  topic,
                  cloned,
                  i
                );
              });
            }
            return quizCopy;
          });
          // accumulate into category-level flat list
          tCopy.quizzes.forEach((q) => flatQuizzesForCategory.push(q));
          // topic-level grouping for convenience
          tCopy.quizSets = chunkInto3(tCopy.quizzes);
        }
        catCopy.topics.push(tCopy);
      });
      // Copy any category-level quizzes (rare) and include in flat list
      if (Array.isArray(cat.quizzes)) {
        catCopy.quizzes = cat.quizzes.map((q) => {
          if (!q || typeof q !== 'object') return q;
          const quizCopy = { ...q };
          if (Array.isArray(quizCopy.questions)) {
            quizCopy.questions = quizCopy.questions.map((question, i) => {
              const cloned =
                question && typeof question === 'object'
                  ? { ...question }
                  : question;
              return ensureQuestionTags(subjectKey, catName, null, cloned, i);
            });
          }
          return quizCopy;
        });
        catCopy.quizzes.forEach((q) => flatQuizzesForCategory.push(q));
      }
      // Derive category-level grouping into sets of 3
      catCopy.quizSets = chunkInto3(flatQuizzesForCategory);
      subjCopy.categories[catName] = catCopy;
    }
    out[subjectKey] = subjCopy;
  }
  return out;
}

app.get('/api/all-quizzes', (req, res) => {
  try {
    res.set('Cache-Control', 'no-store');
    const src = shouldHotReloadAllQuizzes() ? refreshAllQuizzes() : ALL_QUIZZES;
    return res.json(buildAllQuizzesWithTags(src));
  } catch (e) {
    return res.json(ALL_QUIZZES);
  }
});

// Helper function to get random questions from the premade data,
// normalizing challenge_tags using subtopic/category mapping when absent.
const IMAGE_PUBLIC_ROOT = path.join(__dirname, '..', 'frontend', 'public');
const _imageExistsCache = new Map();

function normalizeImageUrlToPublicPath(imgUrl) {
  if (!imgUrl || typeof imgUrl !== 'string') return null;
  const raw = imgUrl.trim();
  if (!raw) return null;
  // ignore external URLs for now (don't block questions on remote assets)
  if (/^https?:\/\//i.test(raw)) return null;
  // remove query/hash
  const noQuery = raw.split('?')[0].split('#')[0];
  let rel = noQuery;
  if (rel.startsWith('/')) rel = rel.slice(1);
  try {
    rel = decodeURIComponent(rel);
  } catch (_) {
    // keep original if decode fails
  }
  return rel || null;
}

function imageExistsForUrl(imgUrl) {
  const rel = normalizeImageUrlToPublicPath(imgUrl);
  if (!rel) return true;
  if (_imageExistsCache.has(rel)) return _imageExistsCache.get(rel);
  const fullPath = path.join(IMAGE_PUBLIC_ROOT, rel);
  const exists = fs.existsSync(fullPath);
  _imageExistsCache.set(rel, exists);
  return exists;
}

function extractImageUrlsFromText(text) {
  if (typeof text !== 'string' || !text) return [];
  const out = [];
  const regex = /src=["']([^"']+)["']/g;
  let match;
  while ((match = regex.exec(text)) !== null) {
    out.push(match[1]);
  }
  return out;
}

function collectQuestionImageUrls(q) {
  if (!q || typeof q !== 'object') return [];
  const content = q.content && typeof q.content === 'object' ? q.content : null;
  const urls = [];

  // Direct/common fields
  const direct = [
    q.imageUrl,
    q.imageURL,
    q.image,
    q.graphic,
    q.stimulusImage && q.stimulusImage.src,
    q.stimulusImage,
    content && (content.imageURL || content.imageUrl || content.image),
  ];
  direct.forEach((u) => {
    if (typeof u === 'string' && u.trim()) urls.push(u.trim());
  });

  // Embedded <img src="..."> in text fields
  const textFields = [
    q.passage,
    q.question,
    q.questionText,
    content && content.passage,
    content && (content.questionText || content.question),
    q.stimulus,
  ];
  textFields.forEach((t) => {
    extractImageUrlsFromText(t).forEach((u) => urls.push(u));
  });

  return urls;
}

function questionHasMissingLocalImage(q) {
  const urls = collectQuestionImageUrls(q);
  if (!urls.length) return false;
  return urls.some((u) => !imageExistsForUrl(u));
}

function getImageMetadataLookup() {
  const lookup = new Map();
  const list = Array.isArray(IMAGE_DB) ? IMAGE_DB : [];
  list.forEach((img) => {
    const key = normalizeImageUrlToPublicPath(img?.filePath || img?.imageUrl);
    if (key) lookup.set(key.toLowerCase(), img);
  });
  return lookup;
}

function getQuestionImageMetadata(question) {
  const urls = collectQuestionImageUrls(question);
  if (!urls.length) return null;
  const lookup = getImageMetadataLookup();
  for (const url of urls) {
    const key = normalizeImageUrlToPublicPath(url);
    if (!key) continue;
    const match = lookup.get(key.toLowerCase());
    if (match) return match;
  }
  return null;
}

function questionHasObviousImageMismatch(question) {
  if (!question || typeof question !== 'object') return false;
  const imageMeta = getQuestionImageMetadata(question);
  if (!imageMeta) return false;

  const text = `${question.question || ''} ${question.questionText || ''}`
    .toLowerCase()
    .trim();
  if (!text) return false;

  const bag = [
    imageMeta.category,
    imageMeta.altText,
    imageMeta.detailedDescription,
    Array.isArray(imageMeta.keywords) ? imageMeta.keywords.join(' ') : '',
    imageMeta.extractedText,
  ]
    .filter(Boolean)
    .join(' ')
    .toLowerCase();

  const modalityChecks = [
    {
      questionRe: /\bphoto(graph)?\b|\bpictured\b|\bshown in the photograph\b/,
      expectedRe:
        /photo|photograph|historical-photos|historic-photos|historical-photographs|crowd|people|portrait|march/,
      bannedRe:
        /map|graph|chart|table|timeline|flowchart|compass|navigation|cartoon|diagram/,
    },
    {
      questionRe: /\bmap\b/,
      expectedRe:
        /map|maps-and-navigation|cartograph|route|border|territor|continent|country|navigation|compass/,
      bannedRe: /graph|chart|table|timeline|flowchart|cartoon|photograph/,
    },
    {
      questionRe: /\bgraph\b|\bbar graph\b|\bline graph\b/,
      expectedRe:
        /graph|bar-graph|bar graph|line-graph|line graph|economics-graphs|demographics-graphs/,
      bannedRe: /cartoon|photograph|map|table|timeline|flowchart/,
    },
    {
      questionRe: /\bchart\b|\bpie chart\b/,
      expectedRe: /chart|pie-chart|pie chart|bar-chart|bar chart/,
      bannedRe: /cartoon|photograph|map|table|timeline|flowchart/,
    },
    {
      questionRe: /\btable\b/,
      expectedRe:
        /table|tables|data table|civics-tables|economics-tables|terminology-table/,
      bannedRe: /cartoon|photograph|map|graph|timeline|flowchart/,
    },
    {
      questionRe: /\bflowchart\b/,
      expectedRe: /flowchart|civics-flowcharts/,
      bannedRe: /cartoon|photograph|map|graph|table|timeline/,
    },
    {
      questionRe: /\btimeline\b/,
      expectedRe: /timeline|timelines/,
      bannedRe: /cartoon|photograph|map|graph|table|flowchart/,
    },
    {
      questionRe: /\bcartoon\b|\bcaricature\b/,
      expectedRe:
        /cartoon|caricature|satire|political-cartoons|political cartoon/,
      bannedRe: /photograph|map|graph|chart|table|flowchart|timeline/,
    },
  ];

  for (const check of modalityChecks) {
    if (!check.questionRe.test(text)) continue;
    if (check.bannedRe.test(bag) && !check.expectedRe.test(bag)) return true;
    if (!check.expectedRe.test(bag)) return true;
  }

  if (/ellis island|immigrant|immigration|naturalization/.test(text)) {
    const immigrationRe =
      /ellis|immigra|naturalization|citizen|refugee|migration/;
    if (!immigrationRe.test(bag)) return true;
  }

  return false;
}

const getPremadeQuestions = (subject, count, options = {}) => {
  const allQuestions = [];
  const targetTier = normalizeLearnerQuestionTier(options?.targetTier);
  const slugify = (value) =>
    (value || '')
      .toString()
      .toLowerCase()
      .replace(/[^a-z0-9]+/g, '-')
      .replace(/^-+/, '')
      .replace(/-+$/, '');

  const pushQuestion = (
    normalized,
    {
      categoryName,
      topicTitle,
      topicId = null,
      originQuizId,
      originQuizTitle,
      originQuizSetLabel = null,
    }
  ) => {
    if (!normalized || typeof normalized !== 'object') return;

    // Ensure topic is never null by falling back to categoryName
    const safeTopic =
      normalized.topic || topicTitle || categoryName || 'General';

    // Ensure quiz title is specific, falling back to topic or category
    const safeOriginQuizTitle =
      originQuizTitle ||
      normalized.originQuizTitle ||
      normalized.quizTitle ||
      topicTitle ||
      categoryName ||
      'Premade Quiz';

    const pathParts = [categoryName, safeTopic];
    if (
      safeOriginQuizTitle &&
      safeOriginQuizTitle !== safeTopic &&
      safeOriginQuizTitle !== categoryName
    ) {
      pathParts.push(safeOriginQuizTitle);
    }

    allQuestions.push({
      ...normalized,
      subject: normalized.subject || subject,
      topic: safeTopic,
      originCategoryName: normalized.originCategoryName || categoryName || null,
      originTopicId: normalized.originTopicId || topicId || null,
      originTopicTitle: normalized.originTopicTitle || safeTopic,
      originQuizId:
        normalized.originQuizId ||
        originQuizId ||
        normalized.quizCode ||
        normalized.quizId ||
        normalized.id ||
        null,
      originQuizTitle: normalized.originQuizTitle || safeOriginQuizTitle,
      originQuizSetLabel: normalized.originQuizSetLabel || originQuizSetLabel,
      originPath:
        normalized.originPath || pathParts.filter(Boolean).join(' / '),
    });
  };

  if (ALL_QUIZZES[subject] && ALL_QUIZZES[subject].categories) {
    Object.entries(ALL_QUIZZES[subject].categories).forEach(
      ([categoryName, category]) => {
        if (category && Array.isArray(category.topics)) {
          category.topics.forEach((topic) => {
            const topicTitle =
              topic?.title || topic?.topic || topic?.name || categoryName;
            const topicId = topic?.id || null;

            // If quiz sets exist, attach origin quiz metadata per set.
            const quizzes = Array.isArray(topic?.quizzes) ? topic.quizzes : [];
            quizzes.forEach((quiz) => {
              if (!quiz) return;
              const setLabel = quiz.label || quiz.setLabel || null;
              const quizTitle =
                quiz.title ||
                quiz.name ||
                (topicTitle && setLabel
                  ? `${topicTitle} (${setLabel})`
                  : topicTitle) ||
                'Premade Quiz';
              const quizId =
                quiz.quizCode ||
                quiz.quizId ||
                quiz.id ||
                `${subject}:${slugify(categoryName)}:${slugify(
                  topicTitle
                )}:${slugify(setLabel || quizTitle)}`;

              const questions = Array.isArray(quiz.questions)
                ? quiz.questions
                : [];
              questions.forEach((q, i) => {
                const cloned = q && typeof q === 'object' ? { ...q } : q;
                const normalized = ensureQuestionTags(
                  subject,
                  categoryName,
                  topic,
                  cloned,
                  i
                );
                // Option B: drop questions that reference missing local images
                if (questionHasMissingLocalImage(normalized)) return;
                if (questionHasObviousImageMismatch(normalized)) return;
                if (normalized.content && normalized.content.questionText) {
                  normalized.question = normalized.content.questionText;
                }
                if (normalized.content && normalized.content.passage) {
                  normalized.passage = normalized.content.passage;
                }
                pushQuestion(normalized, {
                  categoryName,
                  topicTitle,
                  topicId,
                  originQuizId: quizId,
                  originQuizTitle: quizTitle,
                  originQuizSetLabel: setLabel,
                });
              });
            });

            if (Array.isArray(topic?.questions)) {
              topic.questions.forEach((q, i) => {
                const cloned = q && typeof q === 'object' ? { ...q } : q;
                const normalized = ensureQuestionTags(
                  subject,
                  categoryName,
                  topic,
                  cloned,
                  i
                );
                // Option B: drop questions that reference missing local images
                if (questionHasMissingLocalImage(normalized)) return;
                if (questionHasObviousImageMismatch(normalized)) return;
                // Flatten content.questionText to question field for frontend compatibility
                if (normalized.content && normalized.content.questionText) {
                  normalized.question = normalized.content.questionText;
                }
                // Flatten content.passage to passage field for frontend compatibility
                if (normalized.content && normalized.content.passage) {
                  normalized.passage = normalized.content.passage;
                }
                const originQuizId = `${subject}:${slugify(
                  categoryName
                )}:${slugify(topicTitle)}`;
                pushQuestion(normalized, {
                  categoryName,
                  topicTitle,
                  topicId,
                  originQuizId,
                  originQuizTitle: topicTitle,
                });
              });
            }
          });
        }
      }
    );
  }
  const ordered = targetTier
    ? orderQuestionsForTierTarget(allQuestions, targetTier)
    : shuffleArray(allQuestions);
  return targetTier
    ? selectRandomizedTierWindow(ordered, count)
    : ordered.slice(0, count);
};

// Normalize challenge tags from quiz data to match catalog format
function normalizeChallengeTagForCatalog(raw) {
  if (!raw) return '';
  const t = raw.toString().trim().toLowerCase();
  // Our premade data sometimes uses dashes like "rla-2" or "social-1"
  // but the catalog expects colon format like "rla:2" or "social:1".
  // Map simple "<subject>-<num>" to "<subject>:<num>".
  if (/^(rla|math|science|social|social-studies)-\d+$/i.test(t)) {
    return t.replace('-', ':');
  }
  return t;
}

// Validate challenge tags present in premade catalog at startup (warn only)
function validatePremadeChallengeTags() {
  try {
    const subjects = Object.keys(ALL_QUIZZES || {});
    subjects.forEach((subj) => {
      const categories = ALL_QUIZZES[subj]?.categories || {};
      Object.values(categories).forEach((cat) => {
        const topics = Array.isArray(cat?.topics) ? cat.topics : [];
        topics.forEach((topic) => {
          const questions = Array.isArray(topic?.questions)
            ? topic.questions
            : [];
          questions.forEach((q) => {
            const tags = Array.isArray(q?.challenge_tags)
              ? q.challenge_tags
              : [];
            tags.forEach(async (t) => {
              const rawTag = (t || '').toString().trim().toLowerCase();
              if (!rawTag) return;
              const normTag = normalizeChallengeTagForCatalog(rawTag);
              try {
                const exists = await pool.query(
                  'SELECT 1 FROM challenge_tag_catalog WHERE challenge_tag = $1 LIMIT 1',
                  [normTag]
                );
                if (!exists || !exists.rowCount) {
                  console.warn(
                    '[challenge-tag] Not found in catalog:',
                    rawTag,
                    '(normalized:',
                    normTag + ')'
                  );
                }
              } catch (_) {}
            });
          });
        });
      });
    });
  } catch (e) {
    console.warn('validatePremadeChallengeTags failed:', e?.message || e);
  }
}
