function upgradeBulletFallback(bullet = '') {
  const trimmed = String(bullet || '').trim();
  if (!trimmed) return '';
  const hasAction = /^[A-Z][a-z]+/.test(trimmed);
  let upgraded = hasAction ? trimmed : `Completed ${trimmed}`;
  if (!/\d/.test(trimmed)) {
    upgraded = `${upgraded} (add a number if possible)`;
  }
  return upgraded;
}

