// GET /api/admin/students/search - Search and filter students
app.get(
  '/api/admin/students/search',
  authenticateBearerToken,
  requireOrgAdminOrSuper,
  async (req, res) => {
    try {
      const {
        orgId,
        classId,
        active,
        name,
        email,
        phone,
        limit = 25,
        page = 1,
      } = req.query;

      const role = (req.user?.role || '').toLowerCase();
      let targetOrgId;
      if (role === 'super_admin' || role === 'superadmin' || role === 'admin') {
        targetOrgId = orgId ? Number(orgId) : null;
      } else {
        targetOrgId = req.user?.organization_id
          ? Number(req.user.organization_id)
          : null;
      }

      let query = `
      SELECT 
        u.id, 
        u.name, 
        u.email, 
        u.last_login,
        u.created_at,
        NULL::text as phone,
        TRUE as profile_active,
        c.name as class_name,
        qs.math_score,
        qs.science_score,
        qs.rla_score,
        qs.social_score
      FROM users u
      LEFT JOIN profiles p ON p.user_id = u.id
      LEFT JOIN classes c ON p.class_id = c.id
      LEFT JOIN LATERAL (
        SELECT
          MAX(CASE WHEN qa.subject = 'Math' THEN qa.scaled_score END) as math_score,
          MAX(CASE WHEN qa.subject = 'Science' THEN qa.scaled_score END) as science_score,
          MAX(CASE WHEN qa.subject ILIKE '%RLA%' OR qa.subject ILIKE '%Language%' THEN qa.scaled_score END) as rla_score,
          MAX(CASE WHEN qa.subject = 'Social Studies' THEN qa.scaled_score END) as social_score
        FROM quiz_attempts qa
        WHERE qa.user_id = u.id AND qa.scaled_score IS NOT NULL
      ) qs ON true
      WHERE u.role = 'student'
    `;

      const params = [];
      let paramCount = 1;

      if (targetOrgId) {
        query += ` AND u.organization_id = $${paramCount++}`;
        params.push(targetOrgId);
      }

      if (classId) {
        query += ` AND p.class_id = $${paramCount++}`;
        params.push(classId);
      }

      // Note: profiles.active and profiles.phone columns do not exist in the
      // current schema; the `active` and `phone` filters are accepted for
      // forward compatibility but treated as no-ops.
      void active;
      void phone;

      if (name) {
        query += ` AND u.name ILIKE $${paramCount++}`;
        params.push(`%${name}%`);
      }

      if (email) {
        query += ` AND u.email ILIKE $${paramCount++}`;
        params.push(`%${email}%`);
      }

      // Count total
      const countQuery = query
        .replace(/SELECT[\s\S]*?FROM users u/, 'SELECT COUNT(*) FROM users u')
        .replace(/LEFT JOIN LATERAL[\s\S]*?\) qs ON true\s*/, '');
      const countResult = await pool.query(countQuery, params);
      const total = parseInt(countResult.rows[0].count) || 0;

      // Paginate
      const limitNum = Math.min(parseInt(limit) || 25, 100);
      const pageNum = Math.max(parseInt(page) || 1, 1);
      const offset = (pageNum - 1) * limitNum;

      query += ` ORDER BY u.name LIMIT $${paramCount++} OFFSET $${paramCount++}`;
      params.push(limitNum, offset);

      const result = await pool.query(query, params);

      res.json({
        results: result.rows.map((row) => ({
          id: row.id,
          name: row.name,
          email: row.email,
          phone: row.phone,
          className: row.class_name,
          active: row.profile_active !== false,
          createdAt: row.created_at,
          lastLoginAt: row.last_login,
          highestScores: {
            Math: row.math_score != null ? Number(row.math_score) : null,
            Science:
              row.science_score != null ? Number(row.science_score) : null,
            RLA: row.rla_score != null ? Number(row.rla_score) : null,
            'Social Studies':
              row.social_score != null ? Number(row.social_score) : null,
          },
        })),
        total,
        page: pageNum,
        totalPages: Math.ceil(total / limitNum),
      });
    } catch (error) {
      console.error('[/api/admin/students/search] Error:', error);
      res.status(500).json({ error: 'Failed to search students' });
    }
  }
);

// GET /api/admin/students/:id - Get full student profile
app.get(
  '/api/admin/students/:id',
  authenticateBearerToken,
  requireOrgAdminOrSuper,
  async (req, res, next) => {
    try {
      const { id } = req.params;

      // Allow sibling routes like /students/export and /students/search to win
      // when this catch-all is registered earlier in the route table.
      if (!/^\d+$/.test(String(id))) {
        return next();
      }

      const result = await pool.query(
        `
      SELECT 
        u.*,
        p.*,
        c.name as class_name,
        o.name as organization_name
      FROM users u
      LEFT JOIN profiles p ON p.user_id = u.id
      LEFT JOIN classes c ON p.class_id = c.id
      LEFT JOIN organizations o ON u.organization_id = o.id
      WHERE u.id = $1 AND u.role = 'student'
    `,
        [id]
      );

      if (result.rows.length === 0) {
        return res.status(404).json({ error: 'Student not found' });
      }

      const student = result.rows[0];

      // Check access
      if (!canAccessOrganization(req, student.organization_id)) {
        return res.status(403).json({ error: 'Forbidden' });
      }

      // Get latest scores
      const scoresResult = await pool.query(
        `
      SELECT subject, MAX(scaled_score) as highest_score
      FROM quiz_attempts
      WHERE user_id = $1
      GROUP BY subject
    `,
        [id]
      );

      const scores = {};
      scoresResult.rows.forEach((row) => {
        scores[row.subject] = parseInt(row.highest_score);
      });

      res.json({
        id: student.id,
        name: student.name,
        email: student.email,
        phone: student.phone,
        className: student.class_name,
        classId: student.class_id,
        organizationName: student.organization_name,
        organizationId: student.organization_id,
        active: student.active !== false,
        testDate: student.test_date,
        accommodations: student.accommodations || {},
        courseFlags: student.course_flags || {},
        highestScores: scores,
        createdAt: student.created_at,
        lastLogin: student.last_login,
      });
    } catch (error) {
      console.error('[/api/admin/students/:id] Error:', error);
      res.status(500).json({ error: 'Failed to fetch student' });
    }
  }
);

// GET /api/admin/students/:id/quiz-attempts - Get all quiz attempts for a student (admin view)
app.get(
  '/api/admin/students/:id/quiz-attempts',
  authenticateBearerToken,
  requireOrgAdminOrSuper,
  async (req, res) => {
    try {
      const { id } = req.params;
      const { subject, quizType, limit = 50, page = 1 } = req.query;

      // Verify student exists and admin has access
      const studentCheck = await pool.query(
        `SELECT u.id, u.organization_id FROM users u WHERE u.id = $1 AND u.role = 'student'`,
        [id]
      );
      if (studentCheck.rows.length === 0) {
        return res.status(404).json({ error: 'Student not found' });
      }
      if (!canAccessOrganization(req, studentCheck.rows[0].organization_id)) {
        return res.status(403).json({ error: 'Forbidden' });
      }

      let query = `
        SELECT id, subject, quiz_code, quiz_title, quiz_type, score, total_questions, scaled_score, passed, attempted_at
        FROM quiz_attempts
        WHERE user_id = $1
      `;
      const params = [id];
      let paramCount = 2;

      if (subject) {
        query += ` AND subject = $${paramCount++}`;
        params.push(subject);
      }
      if (quizType) {
        query += ` AND quiz_type = $${paramCount++}`;
        params.push(quizType);
      }

      // Count total
      const countResult = await pool.query(
        query.replace(/SELECT .* FROM/, 'SELECT COUNT(*) FROM'),
        params
      );
      const total = parseInt(countResult.rows[0].count) || 0;

      // Paginate
      const limitNum = Math.min(parseInt(limit) || 50, 100);
      const pageNum = Math.max(parseInt(page) || 1, 1);
      const offset = (pageNum - 1) * limitNum;

      query += ` ORDER BY attempted_at DESC LIMIT $${paramCount++} OFFSET $${paramCount++}`;
      params.push(limitNum, offset);

      const result = await pool.query(query, params);

      res.json({
        attempts: result.rows.map(formatQuizAttemptRow),
        total,
        page: pageNum,
        totalPages: Math.ceil(total / limitNum),
      });
    } catch (error) {
      console.error('[/api/admin/students/:id/quiz-attempts] Error:', error);
      res.status(500).json({ error: 'Failed to fetch student quiz attempts' });
    }
  }
);

// POST /api/admin/students - Create new student
app.post(
  '/api/admin/students',
  authenticateBearerToken,
  requireOrgAdminOrSuper,
  async (req, res) => {
    try {
      const {
        firstName,
        lastName,
        email,
        phone,
        classId,
        label,
        courseFlags,
        accommodations,
        passwordMode = 'invite',
      } = req.body;

      if (!firstName || !lastName || !email) {
        return res
          .status(400)
          .json({ error: 'First name, last name, and email are required' });
      }

      // Determine organization
      const role = (req.user?.role || '').toLowerCase();
      let targetOrgId;
      if (role === 'super_admin' || role === 'superadmin' || role === 'admin') {
        targetOrgId = req.body.organizationId || req.user?.organization_id;
      } else {
        targetOrgId = req.user?.organization_id;
      }

      if (!targetOrgId) {
        return res.status(400).json({ error: 'Organization is required' });
      }

      // Check if email exists
      const existingUser = await pool.query(
        'SELECT id FROM users WHERE email = $1',
        [email]
      );
      if (existingUser.rows.length > 0) {
        return res.status(400).json({ error: 'Email already exists' });
      }

      // Create user
      const name = `${firstName} ${lastName}`;
      let passwordHash = null;
      let tempPassword = null;

      if (passwordMode === 'temp') {
        tempPassword = Math.random().toString(36).slice(-8);
        passwordHash = await bcrypt.hash(tempPassword, 10);
      }

      const userResult = await pool.query(
        `
      INSERT INTO users (name, email, password_hash, role, organization_id)
      VALUES ($1, $2, $3, 'student', $4)
      RETURNING id
    `,
        [name, email, passwordHash, targetOrgId]
      );

      const userId = userResult.rows[0].id;

      // Create profile
      await pool.query(
        `
      INSERT INTO profiles (user_id, class_id)
      VALUES ($1, $2)
    `,
        [userId, classId || null]
      );
      // Note: phone, accommodations, course_flags columns do not exist in the
      // profiles schema and are accepted but not persisted.
      void phone;
      void accommodations;
      void courseFlags;

      res.json({
        success: true,
        student: {
          id: userId,
          name,
          email,
          tempPassword: passwordMode === 'temp' ? tempPassword : null,
        },
        message:
          passwordMode === 'invite'
            ? 'Invite email sent (feature pending)'
            : 'Student created with temporary password',
      });
    } catch (error) {
      console.error('[/api/admin/students POST] Error:', error);
      res.status(500).json({ error: 'Failed to create student' });
    }
  }
);

// PUT /api/admin/students/:id - Update student
app.put(
  '/api/admin/students/:id',
  authenticateBearerToken,
  requireOrgAdminOrSuper,
  async (req, res) => {
    try {
      const { id } = req.params;
      const {
        name,
        email,
        phone,
        classId,
        active,
        testDate,
        accommodations,
        courseFlags,
      } = req.body;

      // Check access
      const checkResult = await pool.query(
        'SELECT organization_id FROM users WHERE id = $1',
        [id]
      );
      if (checkResult.rows.length === 0) {
        return res.status(404).json({ error: 'Student not found' });
      }
      if (!canAccessOrganization(req, checkResult.rows[0].organization_id)) {
        return res.status(403).json({ error: 'Forbidden' });
      }

      // Update user
      const userUpdates = [];
      const userParams = [];
      let userParamCount = 1;

      if (name !== undefined) {
        userUpdates.push(`name = $${userParamCount++}`);
        userParams.push(name);
      }
      if (email !== undefined) {
        userUpdates.push(`email = $${userParamCount++}`);
        userParams.push(email);
      }

      if (userUpdates.length > 0) {
        userParams.push(id);
        await pool.query(
          `UPDATE users SET ${userUpdates.join(
            ', '
          )} WHERE id = $${userParamCount}`,
          userParams
        );
      }

      // Update profile (only columns that actually exist in the profiles
      // schema). phone, active, accommodations, and course_flags are accepted
      // for forward compatibility but currently no-op.
      void phone;
      void active;
      void accommodations;
      void courseFlags;
      const profileUpdates = [];
      const profileParams = [];
      let profileParamCount = 1;

      if (classId !== undefined) {
        profileUpdates.push(`class_id = $${profileParamCount++}`);
        profileParams.push(classId);
      }
      if (testDate !== undefined) {
        profileUpdates.push(`test_date = $${profileParamCount++}`);
        profileParams.push(testDate);
      }

      if (profileUpdates.length > 0) {
        profileParams.push(id);
        await pool.query(
          `UPDATE profiles SET ${profileUpdates.join(
            ', '
          )} WHERE user_id = $${profileParamCount}`,
          profileParams
        );
      }

      res.json({ success: true, message: 'Student updated' });
    } catch (error) {
      console.error('[/api/admin/students PUT] Error:', error);
      res.status(500).json({ error: 'Failed to update student' });
    }
  }
);

// GET /api/admin/students/export - Export students CSV
app.get(
  '/api/admin/students/export',
  authenticateBearerToken,
  requireOrgAdminOrSuper,
  async (req, res) => {
    try {
      const { orgId, classId, active } = req.query;

      const role = (req.user?.role || '').toLowerCase();
      let targetOrgId;
      if (role === 'super_admin' || role === 'superadmin' || role === 'admin') {
        targetOrgId = orgId ? Number(orgId) : null;
      } else {
        targetOrgId = req.user?.organization_id
          ? Number(req.user.organization_id)
          : null;
      }

      let query = `
      SELECT 
        u.name, 
        u.email, 
        NULL::text as phone,
        c.name as class_name,
        p.test_date,
        u.created_at,
        u.last_login
      FROM users u
      LEFT JOIN profiles p ON p.user_id = u.id
      LEFT JOIN classes c ON p.class_id = c.id
      WHERE u.role = 'student'
    `;

      const params = [];
      let paramCount = 1;

      if (targetOrgId) {
        query += ` AND u.organization_id = $${paramCount++}`;
        params.push(targetOrgId);
      }

      if (classId) {
        query += ` AND p.class_id = $${paramCount++}`;
        params.push(classId);
      }

      // profiles.active column does not exist; accept the filter but no-op.
      void active;

      query += ` ORDER BY u.name`;

      const result = await pool.query(query, params);

      const csv = [
        'Name,Email,Phone,Class,Test Date,Created At,Last Login',
        ...result.rows.map(
          (row) =>
            `"${row.name}","${row.email}","${row.phone || ''}","${
              row.class_name || ''
            }","${row.test_date || ''}","${row.created_at}","${
              row.last_login || ''
            }"`
        ),
      ].join('\n');

      res.setHeader('Content-Type', 'text/csv');
      res.setHeader(
        'Content-Disposition',
        'attachment; filename="students-export.csv"'
      );
      res.send(csv);
    } catch (error) {
      console.error('[/api/admin/students/export] Error:', error);
      res.status(500).json({ error: 'Failed to export students' });
    }
  }
);

