// ========================================
// ADMIN ANALYTICS ENDPOINTS (item-level)
// ========================================

// GET /api/admin/students/:id/domain-mastery - Per-student domain mastery (admin)
app.get(
  '/api/admin/students/:id/domain-mastery',
  authenticateBearerToken,
  requireOrgAdminOrSuper,
  async (req, res) => {
    try {
      const studentId = parseInt(req.params.id, 10);
      if (!Number.isFinite(studentId))
        return res.status(400).json({ error: 'Invalid student ID' });

      const studentCheck = await pool.query(
        `SELECT u.id, u.organization_id FROM users u WHERE u.id = $1 AND u.role = 'student'`,
        [studentId]
      );
      if (studentCheck.rows.length === 0)
        return res.status(404).json({ error: 'Student not found' });
      if (!canAccessOrganization(req, studentCheck.rows[0].organization_id)) {
        return res.status(403).json({ error: 'Forbidden' });
      }

      const result = await pool.query(
        `SELECT i.subject, i.domain,
                COUNT(*)::int AS total_items,
                SUM(CASE WHEN i.is_correct THEN 1 ELSE 0 END)::int AS correct_items,
                ROUND(AVG(CASE WHEN i.is_correct THEN 1.0 ELSE 0.0 END) * 100, 1) AS accuracy_pct,
                SUM(CASE WHEN i.confidence = 'sure' AND NOT i.is_correct THEN 1 ELSE 0 END)::int AS misconceptions,
                SUM(CASE WHEN i.confidence = 'guessing' AND i.is_correct THEN 1 ELSE 0 END)::int AS lucky_guesses
         FROM quiz_attempt_items i
         JOIN quiz_attempts a ON a.id = i.attempt_id
         WHERE a.user_id = $1 AND i.domain IS NOT NULL
         GROUP BY i.subject, i.domain
         ORDER BY accuracy_pct ASC`,
        [studentId]
      );

      res.json({ studentId, domains: result.rows });
    } catch (error) {
      console.error('[/api/admin/students/:id/domain-mastery]', error);
      res.status(500).json({ error: 'Failed to fetch domain mastery' });
    }
  }
);

// GET /api/admin/students/:id/attempt/:attemptId/items - Admin view of attempt items
app.get(
  '/api/admin/students/:id/attempt/:attemptId/items',
  authenticateBearerToken,
  requireOrgAdminOrSuper,
  async (req, res) => {
    try {
      const studentId = parseInt(req.params.id, 10);
      const attemptId = parseInt(req.params.attemptId, 10);
      if (!Number.isFinite(studentId) || !Number.isFinite(attemptId)) {
        return res.status(400).json({ error: 'Invalid IDs' });
      }

      const studentCheck = await pool.query(
        `SELECT u.id, u.organization_id FROM users u WHERE u.id = $1 AND u.role = 'student'`,
        [studentId]
      );
      if (studentCheck.rows.length === 0)
        return res.status(404).json({ error: 'Student not found' });
      if (!canAccessOrganization(req, studentCheck.rows[0].organization_id)) {
        return res.status(403).json({ error: 'Forbidden' });
      }

      const attempt = await pool.query(
        `SELECT id, subject, quiz_code, quiz_title, quiz_type, score, total_questions, scaled_score, passed, attempted_at
         FROM quiz_attempts WHERE id = $1 AND user_id = $2`,
        [attemptId, studentId]
      );
      if (attempt.rows.length === 0)
        return res.status(404).json({ error: 'Attempt not found' });

      const items = await pool.query(
        `SELECT question_index, question_id, subject, domain, topic,
                challenge_tags, user_answer, correct_answer, is_correct,
                confidence, time_spent_ms, question_type,
                points_earned, points_possible
         FROM quiz_attempt_items
         WHERE attempt_id = $1
         ORDER BY question_index`,
        [attemptId]
      );

      res.json({
        attempt: attempt.rows[0],
        items: items.rows,
      });
    } catch (error) {
      console.error('[/api/admin/students/:id/attempt/:id/items]', error);
      res.status(500).json({ error: 'Failed to fetch attempt items' });
    }
  }
);

// GET /api/admin/reports/domain-weaknesses - Aggregate domain weaknesses across org/class
app.get(
  '/api/admin/reports/domain-weaknesses',
  authenticateBearerToken,
  requireSupportOrAbove,
  async (req, res) => {
    try {
      const { orgId, classId } = req.query;

      const role = normalizeRole(req.user?.role);
      let targetOrgId;
      if (role === 'super_admin') {
        targetOrgId = orgId ? Number(orgId) : null;
      } else {
        targetOrgId = req.user?.organization_id || null;
      }

      let userFilter = '';
      const params = [];
      let paramIdx = 1;

      if (classId) {
        userFilter = `AND a.user_id IN (SELECT user_id FROM class_enrollments WHERE class_id = $${paramIdx++})`;
        params.push(classId);
      } else if (targetOrgId) {
        userFilter = `AND a.user_id IN (SELECT id FROM users WHERE organization_id = $${paramIdx++} AND role = 'student')`;
        params.push(targetOrgId);
      }

      const result = await pool.query(
        `SELECT i.subject, i.domain,
                COUNT(DISTINCT a.user_id)::int AS student_count,
                COUNT(*)::int AS total_items,
                SUM(CASE WHEN i.is_correct THEN 1 ELSE 0 END)::int AS correct_items,
                ROUND(AVG(CASE WHEN i.is_correct THEN 1.0 ELSE 0.0 END) * 100, 1) AS accuracy_pct,
                SUM(CASE WHEN i.confidence = 'sure' AND NOT i.is_correct THEN 1 ELSE 0 END)::int AS misconceptions
         FROM quiz_attempt_items i
         JOIN quiz_attempts a ON a.id = i.attempt_id
         WHERE i.domain IS NOT NULL ${userFilter}
         GROUP BY i.subject, i.domain
         HAVING COUNT(*) >= 5
         ORDER BY accuracy_pct ASC`,
        params
      );

      res.json({ weaknesses: result.rows });
    } catch (error) {
      console.error('[/api/admin/reports/domain-weaknesses]', error);
      res.status(500).json({ error: 'Failed to fetch domain weaknesses' });
    }
  }
);

// The '0.0.0.0' is important for containerized environments like Render.
if (require.main === module) {
  (async () => {
    // Security check: JWT_SECRET must be configured in production.
    // Phase 1.3 — fail-fast instead of warning. Booting without a secret in
    // production is a foot-gun: every issued token would be unverifiable and
    // every authenticated route would 500. Better to refuse to start.
    if (process.env.NODE_ENV === 'production' && !process.env.JWT_SECRET) {
      console.error('');
      console.error('='.repeat(70));
      console.error('CRITICAL: JWT_SECRET is not configured in production!');
      console.error('Authentication will not work without this secret.');
      console.error('Please set JWT_SECRET in your environment variables.');
      console.error('Refusing to start.');
      console.error('='.repeat(70));
      console.error('');
      // Allow an explicit override for emergency debugging only.
      if (process.env.ALLOW_MISSING_JWT_SECRET !== 'true') {
        process.exit(1);
      }
    }

    const desiredPort = port;
    if (await isPortBusy(desiredPort)) {
      if (!process.env.PORT && desiredPort === 3002) {
        const fallback = 3003;
        if (await isPortBusy(fallback)) {
          console.log(
            `Port ${desiredPort} and fallback ${fallback} are already in use. If another backend is running, stop it or set PORT to a free port.`
          );
          process.exit(0);
        } else {
          console.log(
            `Port ${desiredPort} is in use. Starting backend on ${fallback} instead.`
          );
          port = fallback;
        }
      } else {
        console.log(
          `Port ${desiredPort} is already in use. If another backend is running on this port, stop it or choose a different PORT.`
        );
        process.exit(0);
      }
    }

    // ========================================
    // ADMIN API: Fetch all AI questions
    // ========================================
    app.get(
      '/api/admin/all-questions',
      authenticateBearerToken,
      requireSuperAdmin,
      async (req, res) => {
        try {
          const rows = await db.manyOrNone(`
          SELECT id, subject, topic, question_json, created_at
          FROM ai_question_bank
          ORDER BY created_at DESC
        `);

          res.json(rows || []);
        } catch (err) {
          console.error('Failed to fetch AI questions:', err);
          res.status(500).json({ error: 'Unable to load AI question bank' });
        }
      }
    );

    // ========================================
    // ADMIN API: Browse all questions by subject
    // ========================================
    app.get(
      '/api/admin/questions-by-subject',
      devAuth,
      requireSuperAdmin,
      (req, res) => {
        try {
          const { subject } = req.query;

          console.log(
            '[questions-by-subject] Request from user:',
            req.user?.id,
            'role:',
            req.user?.role,
            'subject:',
            subject
          );

          // Map subject aliases to standard keys
          const subjectMap = {
            math: 'Math',
            Math: 'Math',
            science: 'Science',
            Science: 'Science',
            rla: 'Reasoning Through Language Arts (RLA)',
            RLA: 'Reasoning Through Language Arts (RLA)',
            'Reasoning Through Language Arts (RLA)':
              'Reasoning Through Language Arts (RLA)',
            social: 'Social Studies',
            Social: 'Social Studies',
            'Social Studies': 'Social Studies',
            ss: 'Social Studies',
          };

          const subjectKey = subject ? subjectMap[subject] : null;

          if (!subjectKey) {
            return res.status(400).json({
              error: 'Invalid subject. Use: math, science, rla, or social',
            });
          }

          console.log(
            '[questions-by-subject] ALL_QUIZZES keys:',
            Object.keys(ALL_QUIZZES || {})
          );
          console.log(
            '[questions-by-subject] Looking for subjectKey:',
            subjectKey
          );
          console.log(
            '[questions-by-subject] Subject exists:',
            !!ALL_QUIZZES[subjectKey]
          );
          if (ALL_QUIZZES[subjectKey]) {
            console.log(
              '[questions-by-subject] Categories:',
              Object.keys(ALL_QUIZZES[subjectKey].categories || {})
            );
          }

          // Flatten all questions from the subject
          const questions = flattenSubjectQuestions(subjectKey);

          console.log(
            '[questions-by-subject] Found',
            questions.length,
            'questions for',
            subjectKey
          );

          // Add metadata for display
          const enriched = questions.map((q, idx) => ({
            ...q,
            displayNumber: idx + 1,
            subject: subjectKey,
          }));

          return res.json({
            subject: subjectKey,
            totalQuestions: enriched.length,
            questions: enriched,
          });
        } catch (err) {
          console.error('Failed to fetch questions by subject:', err);
          res.status(500).json({ error: 'Unable to load questions' });
        }
      }
    );

    // Register collaboration ("Play Together") REST + socket routes.
    try {
      registerCollabRest(app, {
        authenticateBearerToken,
        getAllQuizzes: () => ALL_QUIZZES,
      });
    } catch (e) {
      console.error('[collab] REST registration failed:', e);
    }

    function startSocketServer(srv) {
      try {
        const io = new SocketIOServer(srv, {
          cors: {
            origin: corsOptions.origin,
            credentials: true,
          },
          path: '/socket.io',
        });
        attachCollabSockets(io, { getAllQuizzes: () => ALL_QUIZZES });
        console.log('[collab] socket.io attached');
      } catch (e) {
        console.error('[collab] socket.io attach failed:', e);
      }
    }

    const httpServer = nodeHttp.createServer(app);
    startSocketServer(httpServer);

    const server = httpServer.listen(port, '0.0.0.0', () => {
      console.log(`Your service is live 🚀`);
      console.log(`Server listening on port ${port}`);
    });

    server.on('error', (err) => {
      if (err && err.code === 'EADDRINUSE') {
        if (!process.env.PORT && port === 3002) {
          const fallback = 3003;
          console.log(
            `EADDRINUSE on ${port}. Attempting fallback port ${fallback}...`
          );
          server.close(() => {
            const fallbackHttp = nodeHttp.createServer(app);
            startSocketServer(fallbackHttp);
            fallbackHttp.listen(fallback, '0.0.0.0', () => {
              port = fallback;
              console.log(`Server listening on fallback port ${port}`);
            });
          });
        } else {
          console.log(
            `EADDRINUSE: address already in use 0.0.0.0:${port}. Not restarting task. Stop the other process or set PORT to a different value.`
          );
          process.exit(0);
        }
      } else {
        console.error('Server error:', err);
        process.exit(1);
      }
    });
  })();
}

module.exports = {
  normalizeLatex,
  applyFractionPlainTextModeToItem,
  replaceLatexFractionsWithSlash,
};
